INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (196, '5', '일기예보관', '연구직 및 공학 기술직', '일기예보관은 각종 기상 관측 자료의 분석을 바탕으로 일기예보와 기상현상에 대한 주의보, 경보, 기상 전망을 발표하는 업무를 수행합니다. 기류의 방향, 속도, 온도, 습도, 기압 등 지구 대기의 물리적 특성과 그 특성에 영향을 미치는 요인을 조사하여 일기도를 작성합니다. 기상 관측 자료의 분석을 통해 장기, 단기 일기예보와 기상현상에 대한 주의보, 경보, 기상 전망을 발표합니다.', '["대기과학과","천문학과"]', 46620000, '향후 5년간 일기예보관의 관련 직업인 천문·기상학연구원의 일자리 규모는 다소 증가할 것으…', '["기상예보기술사","기상기사","기상감정기사"]', '이학 전문직', '2026-04-06 07:46:55.699094');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (197, '8', '물리학연구원', '연구직 및 공학 기술직', '물리학연구원은 자연현상의 기본 법칙을 규명하여 합리적으로 설명, 예측하고, 물리학적 원리와 기법을 산업, 의료, 군사 분야 등에 응용하기 위한 연구를 수행합니다. 물질과 구조의 운동, 전기나 빛 등 에너지의 발생과 이동, 물질과 에너지의 상호 관계에 대한 연구와 실험을 합니다. 물질과 에너지의 관계 등 물리학적 현상에 대해 관찰, 실험합니다. 고형 물질의 구조와 특성을 조사하기 위해 온도, 압력 등의 환경조건을 변화시켜 실험하고 반응을 연구합니다. 다양한 물리학적 기본 원리를 적용하여 재료, 전기, 자기, 광학, 의료, 음향, 빛 등 일상생활을 편리하게 하는 기구 개발에 대해 연구합니다.', '["물리학과","지구환경과학과"]', 67340000, '향후 5년간 물리학연구원의 일자리 규모는 다소 증가할 것으로 전망됩니다. 정부가 국가경쟁…', '[]', '이학 전문직', '2026-04-06 07:46:56.050912');
