INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (200, '17', '수학연구원', '연구직 및 공학 기술직', '수학연구원은 수학적 지식과 이론에 대해 연구하며, 수학적 이론과 기법을 활용하여 경제학, 과학, 공학 등의 문제를 해결하기 위한 연구를 수행합니다. 대수학, 기하학, 확률과 같은 전통적인 수학 분야와 자연과학, 엔지니어링, 컴퓨터공학, 경영과 같은 기타분야의 문제해결을 위한 응용수학기술 분야 등에서 수학적 지식을 확장하기 위한 연구를 수행합니다. 순수수학연구원은 자연현상을 관찰해 얻어진 일반적인 생각을 논리적인 모순이 없는 수학적 모형으로 만든 다음 그 모형을 분석해서 이론을 개발합니다. 응용수학연구원은 순수수학 연구를 통해 얻어진 수학적 모형을 암호학, 컴퓨터 공학, 엔지니어링, 금융 수학 등에 적용하는 연구를 수행합니다.', '["수학과","통계학과"]', 53870000, '향후 5년간 수학연구원의 관련 직업인 수학·통계학연구원의 일자리 규모는 다소 증가할 것으…', '[]', '이학 전문직', '2026-04-06 07:46:57.121203');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (201, '20', '심리학연구원', '보건·의료직', '심리학연구원은 인간의 행동과 정신적 과정을 과학적으로 연구하고, 연구 결과를 의학, 교육, 산업 현장에 적용할 수 있는 심리학적 지식과 정보를 제공합니다. 인간과 동물에 관한 실험과 관찰을 계획하고 수행합니다. 지능, 능력, 적성, 인성, 기타 인간 행동을 측정하는 검사를 개발하고 시행하며, 검사 자료를 분석하고 해석합니다. 환경과 개인의 사상, 행동에 관한 요소 등을 분석합니다. 의학, 교육, 산업 현장에서 나타날 수 있는 다양한 인간의 심리학적 문제를 연구하고 해결 방안을 제시합니다.', '["심리학과"]', 56980000, '향후 5년간 심리학연구원의 일자리 규모는 다소 증가할 것으로 전망됩니다. 최근 들어 인공…', '[]', '인문 및 사회과학 관련직', '2026-04-06 07:46:57.474341');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (202, '23', '약사 및 한약사', '연구직 및 공학 기술직', '약사는 의사의 처방전이나 공인된 조제 방법에 의해 약을 조제하고, 환자나 보호자를 대상으로 질병 치료와 건강 유지에 대한 상담 업무를 수행하며, 한약사는 한약 및 한약제제의 생산, 제조, 조제, 유통, 가공, 연구, 판매 등의 업무를 수행합니다. 의사의 처방전에 이상이 없는지 확인한 후 약물의 무게와 양을 측정하여 제조합니다. 조제된 약의 복용 시 주의 사항, 부작용 위험 등을 설명하면서 투여 경로, 투여량, 투여 간격 등 복용 방법을 확인시켜 줍니다. 제약회사에 근무하는 경우 새로운 의약품을 연구, 개발하고 약품의 효능을 재평가하거나 부작용을 연구합니다. 공공기관, 연구원 등에 근무하는 경우 새로운 화학물질 등의 사용 여부에 대한 기준을 제공하고, 마약, 독약, 부정 의약품 등의 성분을 분석하고 감식합니다.', '["약학부","한약학과"]', 65000000, '향후 5년간 약사 및 한약사의 관련 직업인 약사의 일자리 규모는 다소 증가할 것으로 전망…', '["약사","한약사"]', '의료관련 전문직', '2026-04-06 07:46:57.821096');
