INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (204, '29', '지리학연구원', '연구직 및 공학 기술직', '지리학연구원은 지표상 나타나는 자연, 인문적 현상의 공간적 분포 양식, 형성 과정, 상호 연관성에 대해 연구합니다. 자연, 인문적 현상이 지표상 어디에서 발생하고, 왜 특정 장소에서 특정 형태로 발생하는지에 대해 여러 이론과 분석을 통해 원인을 규명합니다. 지역 답사 활동을 통해 특정 지역의 자연환경과 기후조건의 특징을 조사, 연구합니다. 측량 장비와 기상학적 도구를 사용하여 지도, 도표 도식을 작성하고 해석합니다. 지역의 경제적 개발, 경제적 및 자연적 경계의 결정과 같은 문제에 대해 조언하고 자문합니다.', '["지리학과"]', 40700000, '향후 5년간 지리학연구원의 관련 직업인 지리정보시스템(GIS: Geographic Inf…', '[]', '이학 전문직', '2026-04-06 07:46:58.525418');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (223, '86', '생물공학연구원', '설치·정비·생산직', '생물공학연구원은 미생물, 동식물, 효소를 이용하여 물질을 생산, 분해, 변환하고 이를 통해 얻은 지식과 기술을 인간 생활에 응용하는 연구를 담당합니다. 의학, 약학, 화공, 환경공학 등의 전문가들과 협동하여 유전자 재조합, 생물 공정 등 이미 개발된 기술을 습득하고 새로운 생물공학기술을 개발하는 연구를 수행합니다. DNA 조작을 통해 신물질 개발 실험을 하거나, 실험동물의 체세포나 혈액을 분리 및 조작하는 실험을 통해 새로운 생물의약품, 생물화학제품, 바이오식품 등의 신제품을 개발합니다.', '["생명과학과","생명공학과"]', 48350000, '향후 5년간 생물공학연구원의 관련 직업인 생물학연구원의 일자리 규모는 다소 증가할 것으로…', '["바이오화학제품제조기사"]', '이학 전문직', '2026-04-06 07:47:05.286424');
