INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (205, '32', '측량사', '보건·의료직', '측량사는 국토의 이용, 개발, 건설 공사, 지도 제작을 목적으로 토지의 형태, 지형선, 위치, 고도, 면적 등을 측량하는 업무를 수행합니다. 토지에 대한 측량 계획과 방법, 절차를 계획함으로써 토지에 물권이 미치는 한계를 정합니다. 토지 자산, 필지, 토지구획에 대한 사법적 경계를 확립하고자 측량을 계획, 지휘, 감독합니다. 지형, 지형선 등 영역들을 도면화하고자 경도, 각도, 컴퓨터 삼각법, 기타 계산을 활용하여 분석합니다. 측량 자료를 검토, 수정하여 도면과 측량 결과서를 작성합니다.', '["건축공학과","지구정보공학과","측지정보과","기계공학과","도시공학과","물리학과","지구환경과학과","통계학과","천문학과","수학과","토목공학과","지적과","건축학과","건축과","지적학과","지리학과"]', 50000000, '향후 5년간 측량사의 일자리 규모는 다소 감소할 것으로 전망됩니다. 리모델링과 재건축 공…', '["측량기능사","측량및지형공간정보기사","측량및지형공간정보기술사","측량및지형공간정보산업기사","지적기술사","지적기사","지적산업기사"]', '공학 기술직', '2026-04-06 07:46:58.881104');
