INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (207, '38', '해부학연구원', '연구직 및 공학 기술직', '해부학연구원은 사람과 동물의 해부학적 특성을 분석하여 의학과 관련 분야에 적용하기 위한 연구를 수행합니다. 해부 실습을 통해 사람과 동물의 신체 구조, 해부학적 특성에 대해 연구합니다. 인체의 정상 구조와 각 장기들의 상호 관계, 의학교육에 필요한 기초 지식을 쌓을 수 있도록 대학에서 학생들을 가르칩니다.', '["수의학과","생화학과","생물학과","의예과"]', 45790000, '향후 5년간 해부학연구원의 관련 직업인 의학연구원의 일자리 규모는 현 상태를 유지하거나 …', '[]', '이학 전문직', '2026-04-06 07:46:59.588653');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (208, '41', '가전제품 설치 및 수리원', '보건·의료직', '가전제품 설치 및 수리원은 서비스 센터 내에 근무하면서 방문하는 고객의 제품을 수리하거나 고객의 집을 방문하여 수리하는 업무를 수행합니다. 고객의 수리 신청이 접수되면 접수된 내용을 확인하고 고객과의 소통을 통해 제품의 문제를 확인합니다. 제품의 파손 부위를 확인하고 공구를 사용하여 교체하거나 수리합니다. 가전제품의 시운전을 통해 작동상태를 확인하고 수동 공구를 사용하여 재조립합니다. 교체한 부품의 종류와 수량을 작업일지에 기록하고 수리 비용을 산출합니다.', '["전자공학과","전기공학과","전기과","전기전자과","전기전자공학과","전자과"]', 36630000, '향후 5년간 가전제품 설치 및 수리원의 일자리 규모는 다소 감소할 전망입니다. 기술 발전…', '["전기산업기사","전기응용기술사","전자기능사","전자기능장","전자기사","전자산업기사","전자응용기술사"]', '기능직', '2026-04-06 07:46:59.937347');
