INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (210, '47', '타이어 및 고무제품 생산직', '연구직 및 공학 기술직', '타이어 및 고무제품 생산직은 각종 고무 제품 제작을 위해 여러 화학제품과 원료를 배합, 가공하는 제조기기와 장치를 조작합니다. 작업지시서에 따라 필요한 고무나 고무 화합물을 준비하여 계량합니다. 압출, 성형된 고무 부품을 작업대 위에 올려놓고, 부품의 제조 상태를 점검하여 파손되거나 규격 미달인 제품을 제거합니다. 컨베이어벨트나 작업대 위에 고무 부품을 조립하기 쉽게 늘어놓고, 홈이나 틀에 맞추어 주름이 발생하지 않도록 합니다. 고무 제품 제조기기 조작을 통해 기계장치의 온도, 압력, 속도 등을 조정하고, 완성된 고무 제품의 품질을 검사합니다.', '["기계과","화학공업과","화학과"]', 38850000, '향후 5년간 타이어 및 고무제품 생산직의 관련 직업인 타이어 및 고무제품 생산기조작원의 …', '[]', '기능직', '2026-04-06 07:47:00.64471');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (211, '50', '제화원', '연구직 및 공학 기술직', '제화원은 가죽, 인조가죽 등의 재료를 이용해서 각종 구두, 가방, 벨트 등의 제품을 생산하고 수선하는 업무를 담당합니다. 고객의 주문서와 작업지시서에 따라 제품 디자인, 크기, 수량을 확인하고 필요한 재료와 공구를 준비합니다. 제품의 모형을 만들고, 모형에 따라 가죽 또는 인조가죽 등의 재료를 재단하며, 접착제와 재봉틀을 이용하여 형태를 고정합니다. 바닥을 매끄럽게 다듬고 고무 밑창을 접착시키며, 구두의 깔창을 부착하거나 가방의 끈을 다는 등 마무리 작업을 합니다. 완성된 제품의 품질과 결함 여부를 검사하며 낡은 구두나 가방 등을 수선하기도 합니다.', '[]', 35000000, '향후 5년간 제화원의 일자리 규모는 다소 감소할 것으로 전망됩니다. 수제로 만든 구두를 …', '["신발제조기능사"]', '의복제조 관련직', '2026-04-06 07:47:01.001123');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (212, '53', '금속공학기술자', '연구직 및 공학 기술직', '금속공학기술자는 금속, 합금의 제조와 가공 방법 개발을 위해 금속의 물리적, 조직적 특성을 실험하고 연구하며, 장단기 기술개발 계획을 수립하는 업무를 수행합니다. 금속제품의 제조, 가공, 합금 등 금속 분야에 대한 자료를 수집, 분석해서 신기술을 개발하고 생산기술을 향상시키는 역할을 수행합니다. 금속의 주형, 조형, 열처리를 위한 공정을 설계합니다. 금속을 응집, 추출, 제련, 처리하기 위한 공정을 계획하고 설계합니다. 기존 설비를 확장 및 증설하는 금속 설비 계획을 판단하여 보고합니다.', '["재료공학과","신소재공학과","제철금속과","금속공학과"]', 50000000, '향후 5년간 금속공학기술자의 관련 직업인 재료공학기술자의 일자리 규모는 현 상태를 유지할…', '["금속가공기술사","금속재료기사","금속재료기능장","금속재료기술사","금속재료산업기사","금속재료시험기능사","열처리기능사","원형기능사","주조기능사","주조기능장","주조산업기사","자동화설비산업기사","자동화설비기능사","자기비파괴검사기능사","자기비파괴검사기사","자기비파괴검사산업기사","화공기사","화공기술사","기계조립산업기사","전기기사","전기산업기사","정밀측정산업기사","초음파비파괴검사기사","초음파비파괴검사산업기사"]', '공학 전문직', '2026-04-06 07:47:01.356645');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (225, '92', '선박정비원', '건설·채굴직', '선박정비원은 선박기계를 정비, 점검하고 선박의 고장 상태를 확인하며 수리합니다. 검사 기구를 이용하여 선박의 각 부분을 진단 및 점검하고, 고장의 위치나 범위, 고장의 정도 등을 확인합니다. 검사를 통해 파악된 고장 부위를 수리하고, 마모되거나 파손된 파이프, 철판 등의 부품을 새 부품으로 교체합니다. 연료, 오일 및 기타 보급품을 채우며 수리 부분의 작동상태를 최종 확인합니다.', '["기계공학과","기계과"]', 38670000, '향후 5년간 선박(엔진)정비원의 일자리 규모는 다소 감소할 전망입니다. 국민 생활수준의 …', '["동력기계정비기능사"]', '기능직', '2026-04-06 07:47:06.029746');
