INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (213, '56', '기계공학 기술자ㆍ연구원', '보건·의료직', '기계공학 기술자ㆍ연구원은 다양한 산업과 연관된 기계, 기구, 산업 설비, 생산시스템 등을 연구, 개발, 설계, 제조하고, 생산 공정을 운영, 감독하는 업무를 수행합니다. 기계의 구성 요소, 설계, 운영, 성능, 시스템의 실현 가능성에 관해 연구하고, 제품에 대한 아이디어를 기획하며, 세부 사항을 설계합니다. 산업 설비와 건설 현장의 기계 시스템의 설비, 변경, 위탁을 감독하고 검사합니다. 기계의 고장이나 문제를 파악하고 해결하며 기술자와 엔지니어를 감독합니다. 계산, 비용 견적서, 보고서 등을 작성하고 검토하는 업무를 수행합니다.', '["자동차공학과","기계설계공학과","기계공학과","조선공학과","항공우주공학과"]', 51000000, '향후 5년간 기계공학 기술자ㆍ연구원의 관련 직업인 건설기계공학기술자의 일자리 규모는 현 …', '["건설기계설비기사","건설기계기술사","건설기계설비산업기사","기계기술사","기계설계산업기사","농업기계기사","농업기계산업기사","전산응용기계제도기능사","기계설계기사"]', '공학 전문직', '2026-04-06 07:47:01.708066');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (214, '59', '녹음기사', '보건·의료직', '녹음기사는 영화, 텔레비전, 라디오 등에서 사용되는 음악, 배경음, 대사 등을 녹음하는 장비를 조작하는 업무를 수행합니다. 촬영 장소에 대한 사전 답사를 통해 주변 환경을 확인하고 촬영에 대한 대비를 제작진에게 요구합니다. 촬영 시 가장 적절한 위치에 마이크를 설치해서 소리를 명료하게 녹음하고, 배우의 대사 톤을 세심히 살펴 톤이 일관되게 유지될 수 있도록 돕는 역할을 수행합니다. 녹음기의 가동 상태를 확인하고 조작하여 프로그램의 음향을 녹음테이프에 수록합니다. 편집기 조작을 통해 프로그램의 화면과 음향을 재편집하기도 하며, 기기의 작동 상태를 점검합니다.', '["방송제작과","음향제작과","방송영상과","영상제작과"]', 39370000, '향후 5년간 녹음기사의 관련 직업인 음향 및 녹음기사의 일자리 규모는 현 상태를 유지할 …', '[]', '음악 관련직', '2026-04-06 07:47:02.063708');
