INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (216, '65', '건물도장원', '보건·의료직', '건물도장원은 건축 구조물의 표면에 페인트, 라커 등을 입혀 건축물을 아름답고 오랫동안 보존할 수 있도록 합니다. 도장 당일의 온도, 습도, 바람, 환기 조건 등의 환경조건을 살피고, 도면이나 지시서를 숙지합니다. 도장 시 공면을 매끄럽게 하기 위하여 장비를 사용하여 묵은 페인트나 거친 부위를 긁어냅니다. 페인트에 희석제를 섞거나 색조를 혼합하고 솔, 롤러, 분사기 등을 사용하여 지정된 표면에 페인트를 칠합니다.', '["건축과","토목과","도시건설과","건축공학과"]', 37300000, '향후 5년간 건물도장원의 일자리 규모는 현 상태를 유지하거나 다소 감소할 것으로 전망됩니…', '["건축도장기능사"]', '기능직', '2026-04-06 07:47:02.786248');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (217, '68', '목공', '연구직 및 공학 기술직', '목공은 목재 등 자재를 깎고 조립하여 건축의 지붕틀, 방음 설비, 마루, 칸막이, 내외장 마감과 같은 건축물의 내외부 공사에 필요한 목재 작업을 담당합니다. 건축 설계 도면과 공작 도면에 따라 목재의 치수를 측정하고 절단하며, 마름질용 기계를 사용하여 목재를 다듬습니다. 다듬은 목재를 목조주택의 지붕, 전통 목조건축물의 복원, 수리 등의 목적에 따라 조립합니다.', '[]', 40000000, '향후 5년간 목공의 관련 직업인 건축목공의 일자리 규모는 현 상태를 유지할 것으로 전망됩…', '["거푸집기능사","건축목공기능사","건축목공산업기사","건축목재시공기능장","국가유산수리기능자"]', '기능직', '2026-04-06 07:47:03.143661');
