INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (219, '74', '배관원', '연구직 및 공학 기술직', '배관원은 건축물에 물, 가스, 증기, 기타 물질을 운반하는 배관시설을 제작, 설치하고, 배관시설의 유지보수와 관련된 업무를 수행합니다. 건물 설계도와 도면을 검토하고 현장을 검증하여 배관설비에 필요한 재료, 장비, 노동력 등을 판단합니다. 배관설비의 구조 도면에 따라 파이프를 절단, 가공하고, 배관시설을 설비할 곳에 구멍을 뚫어 배관 파이프를 설비하며, 파이프 간의 연결 부위를 봉합하고 용접하여 밀봉합니다. 오래되어 낡거나 고장이 난 건물의 배관시설을 수리하고 교체합니다. 누수 또는 결함 부위를 찾아내기 위하여 배관시설을 점검합니다.', '["산업설비자동화과","건축공학과","금형설계과"]', 37150000, '향후 5년간 배관원의 관련 직업인 건설배관공의 일자리 규모는 현 상태를 유지할 것으로 전…', '["배관기능장","배관산업기사","배관기능사"]', '기능직', '2026-04-06 07:47:03.860544');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (220, '77', '건설기계운전원', '설치·정비·생산직', '건설기계운전원은 건설 공사에 필요한 다양한 작업을 위해 각종 건설 기계를 운전합니다. 작업지시서 또는 작업 현장을 파악하여 작업에 필요한 부품, 작업시간, 작업 절차 등을 결정합니다. 기계의 작동상태를 검사하고 작업지시에 따라 건설기계를 조종합니다. 예정된 절차와 순서에 따라 중기를 운전 및 조작하여 작업을 수행합니다. 불도저, 굴착기, 지게차, 기중기 등의 기계를 조작합니다.', '["제어계측공학과","기계과","제어계측과","전기과","전기전자과","기계공학과","전기공학과","전기전자공학과"]', 41440000, '향후 5년간 건설기계운전원의 관련 직업인 건설·채굴기계운전원의 일자리 규모는 다소 감소할…', '["굴착기운전기능사","로더운전기능사","롤러운전기능사","모터그레이더운전기능사","불도저운전기능사","아스팔트피니셔운전기능사","지게차운전기능사"]', '일반운전 관련직', '2026-04-06 07:47:04.225537');
