INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (222, '83', '산업공학기술자', '연구직 및 공학 기술직', '산업공학기술자는 기업경영에 대하여 사회과학적 전문 지식과 자연과학적 원리를 응용하여 경영의 여러 요소를 과학적으로 분석하고 조정하는 업무를 수행합니다. 생산을 위한 최적의 수준을 결정하고 기계, 원자재, 자원의 최적 활용을 위한 프로그램을 실행합니다. 경영 기획, 기술 전략, 경영 정보 시스템 분야 등에서 회사에 영향을 끼치는 다양한 요인들을 분석하고 사업전략과 경영관리 방법을 모색합니다. 시설을 계획하고 설계하며 새로운 기계, 설비를 연구하고 적용합니다.', '["전기전자공학과","기계설계공학과","기계공학과","산업공학과","전기공학과","안전공학과"]', 40000000, '향후 5년간 산업공학기술자의 일자리 규모는 다소 증가할 것으로 전망됩니다. 4차 산업혁명…', '["산업안전기사","산업안전산업기사","산업안전지도사","품질경영산업기사","공장관리기술사","품질경영기사"]', '공학 전문직', '2026-04-06 07:47:04.928569');
