INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (227, '98', '신경회로망연구원', '설치·정비·생산직', '신경회로망연구원은 영상 및 음성인식, 로봇 제어, 통신 등에 사용되는 인공지능형 반도체 및 응용기술을 연구하고 개발하는 일을 담당합니다. 인간의 뇌와 뇌세포 구조에 대한 지식을 바탕으로 컴퓨터나 로봇 등이 인간과 같이 사고하고 학습하는 능력을 갖도록 하는 프로그램을 개발하고 연구합니다. 영상인식, 음성인식, 로봇제어, 표적인식, 통신 등에 사용되는 응용기술을 연구합니다.', '["전자공학과","기계공학과","컴퓨터공학과","재료공학과","전기공학과"]', 46620000, '신경회로망연구원의 관련 직업인 반도체공학기술자의 일자리 규모는 다소 증가할 것으로 전망됩…', '[]', '공학 전문직', '2026-04-06 07:47:06.75307');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (228, '101', '영사기사', '연구직 및 공학 기술직', '영사기사는 영화가 상영될 수 있도록 필름을 영사기에 연결하고 가동하는 일을 담당합니다. 영사기를 점검 및 가동하고 영사전등과 렌즈를 조절하며 음향 재생 장비를 조정합니다. 영화의 상영이 끝난 다음에는 필름을 되감고, 필름의 손상 여부를 확인해 이를 수선합니다.', '["영상제작과","방송제작과","연극영화과","방송영상과","연극영화학과"]', 37500000, '향후 5년간 영사기사는 디지털 기술의 적용으로 인력 수요가 점점 사라질 것으로 전망됩니다…', '["영사기능사","영사산업기사"]', '영상 관련직', '2026-04-06 07:47:07.101781');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (229, '104', '원자력연구원', '설치·정비·생산직', '원자력연구원은 사람들과 산업체에 에너지를 제공하기 위해 사용되는 원자력의 안전한 이용 방법에 대해 연구하고 개발합니다. 안전성과 경제성을 지닌 새로운 원자력 에너지를 연구ㆍ개발하며, 원자력 발전소의 안전성을 평가합니다. 방사선 폐기물의 안전한 처리 방법에 대해 연구하고, 방사선을 의학용, 농업용 등으로 이용할 수 있는 기술을 개발합니다. 화학, 생물 등의 기초 분야 및 인공지능, 신소재 개발과 같은 여러 분야와 원자력 기술을 접목하는 연구를 수행합니다.', '["원자력공학과"]', 54500000, '향후 5년간 원자력공학기술자의 일자리 규모는 현 상태를 유지할 것으로 전망됩니다. 원자력…', '["원자력기사","원자력발전기술사","핵연료물질취급자"]', '공학 전문직', '2026-04-06 07:47:07.463403');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (230, '107', '인공위성개발원', '연구직 및 공학 기술직', '인공위성개발원은 우주탐사, 기상예보 등의 다양한 목적을 달성하기 위한 인공위성을 연구 및 개발하는 일을 담당합니다. 인공위성 및 인공위성과 관련된 분야에 대한 전문적 지식과 기술을 활용하여 목적에 맞는 인공위성을 연구, 개발, 설계합니다. 인공위성이 궤도에 도달하도록 유도하며, 위성으로부터 보내진 탐사 자료를 분석합니다. 시장조사와 세계 인공위성개발의 기술 변화 등에 대해 분석하여 인공위성의 기술적 성능의 개선 및 개발에 참고합니다. 개발한 인공위성의 성능을 시험하며, 발견된 인공위성의 결함 원인에 대해 분석하여 해결책을 제시합니다.', '["항공우주공학과","재료공학과","물리학과","제어계측과","화학과","전자공학과"]', 42000000, '향후 5년간 인공위성개발원의 일자리 규모는 다소 증가할 전망입니다. 인공위성은 방송, 통…', '[]', '공학 전문직', '2026-04-06 07:47:07.823687');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (231, '110', '자동차조립원', '연구직 및 공학 기술직', '자동차조립원은 각종 자동차의 차체, 외·내장품, 타이어, 유리 등의 부품들을 조립 및 부착하여 자동차를 완성하거나 완성된 자동차 조립품을 검사합니다. 작업 표준서를 보고 필요한 공구 및 자재를 확인하고, 도장이 끝난 차체에 동력 공구를 이용하여 각종 내장 부품, 배선, 트림 등을 조립합니다. 차량의 앞, 뒤 유리와 옆문 유리, 제동장치, 엔진, 변속기를 조립합니다. 타이어, 앞뒤 범퍼, 전조등, 제동등 등 외장 부품을 조립하고, 운전석과 조수석 내부 의자를 조립합니다. 자동차의 부품 및 최종 자동차 생산품을 검사하고, 최종 자동차 생산품이 품질 기준에 적합한지를 확인합니다.', '["자동차공학과","자동차정비과"]', 49730000, '향후 5년간 자동차조립원의 일자리 규모는 현 상태를 유지할 것으로 전망됩니다. 우리나라의…', '["자동차정비기능사","자동차정비산업기사","자동차정비기사"]', '기능직', '2026-04-06 07:47:08.19448');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (232, '113', '전공', '설치·정비·생산직', '전공은 발전소에서 주택이나 상가, 공장까지 전기가 안전하게 전달되어 사용될 수 있도록 각종 전력시설을 설치하고 수리합니다. 전기공사에 관한 기초적인 지식과 숙련기능을 소지하고 전기공사용 기자재와 측정기를 사용하여 고압선이나 저압선을 가설하여 지지물 및 기기를 설치·보수합니다. 분야에 따라 외선전공, 내선전공, 산업전공으로 분류됩니다.', '["전기공학과","전기과","전기전자공학과"]', 38850000, '향후 5년간 전공의 관련 직업인 내선전기공의 일자리 규모는 현 상태를 유지할 전망입니다.…', '["건축전기설비기술사","전기공사산업기사","전기공사기사","전기산업기사","전기기사"]', '공학 기술직', '2026-04-06 07:47:08.553093');
