INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (234, '119', '전자공학기술자', '연구직 및 공학 기술직', '전자공학기술자는 물리학 및 수학의 이론과 원리를 바탕으로 재료 속성에 대한 지식을 활용하여 전자제품을 설계 및 개발하고 생산관리 및 감독 업무를 합니다. 제품을 설계 및 개발하기 위해서는 시장조사를 거쳐 소비자가 원하는 성능, 기능, 디자인 등에 대한 의견 수렴을 하고 경쟁업체 제품 및 세계 동향, 기술 변화 등을 분석한 후 디자인 설계를 합니다. 계획된 공사의 설계와 시공에 대한 감독 및 조언을 담당하고 계측제어설비에 대한 정비 계획을 수립·시행합니다. 전산기 하드웨어 및 계측제어설비의 사양을 검토·조정하고 신기술 도입 및 개발 방안을 연구합니다. 제품의 모델을 만들어 성능에 이상은 없는지, 제대로 작동은 하는지, 진동이나 충격에 강한지 등을 테스트합니다.', '["전기과","전기전자공학과","전기전자과","전자공학과","전자과"]', 46310000, '향후 5년간 전자공학기술자의 일자리 규모는 다소 증가할 전망입니다. 전자공학 기술을 활용…', '["산업계측제어기술사","전자산업기사","전자기사","전자기능장","전자응용기술사","전자계산기기사","컴퓨터시스템응용기술사","전자계산기제어산업기사","전자회로설계산업기사"]', '공학 전문직', '2026-04-06 07:47:09.275307');
