INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (235, '122', '정밀기기제품제조원', '건설·채굴직', '정밀기기제품제조원은 각종 센서, 제어장치 등의 부품을 제작 및 조립하여 현미경, 시계, 카메라 등, 모양은 작지만 다양한 기능을 갖춘 기기들을 제조하는 일을 담당합니다. 작업지시서에 따라 센서, 제어장치 등의 부품들을 제작하고 조립하여 현미경, 카메라, 의료 영상기기 등의 제품을 생산합니다. 정밀 측정기구를 사용하여 부품의 품질, 완성된 제품의 조립 이상 유무 등을 검사합니다.', '["기계공학과","제어계측공학과","전기공학과"]', 43500000, '향후 5년간 정밀기기제품제조원의 관련 직업인 전기제품개발기술자의 일자리 규모는 다소 증가…', '["광학기능사","광학기사"]', '기능직', '2026-04-06 07:47:09.624921');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (236, '125', '캐드원', '설치·정비·생산직', '캐드원은 공학기술자나 설계사가 작성한 스케치와 명세서를 가지고 캐드(컴퓨터 지원 설계, CAD: Computer Aided Design)를 활용하여 건축토목용 시공도나 기계, 전기, 전자 장비 및 제품의 제조와 설치에 필요한 세부 도면을 작성합니다. 약도나 설계서의 내용을 파악하여 캐드 작업을 제품, 기계, 특수, 정밀 도면으로 분류합니다. 공학적 계산을 수행하고 명세서 및 기타 자료로부터 설계 스케치를 계획합니다. 완성된 도면으로 컴퓨터상에서 투시도 또는 3차원 시뮬레이션으로 재현하기도 합니다. 설계 도면이 명세서 및 설계 자료와 일치하는지, 틀린 곳은 없는지 등을 검사합니다.', '["건축공학과","건축과","건축학과","섬유공학과","컴퓨터공학과","토목공학과"]', 37750000, '향후 5년간 캐드원의 관련 직업인 제도사의 일자리 규모는 현 상태를 유지하거나 다소 감소…', '["전산응용건축제도기능사","건축산업기사","실내건축산업기사","건축기사","실내건축기능사","실내건축기사","전산응용조선제도기능사","토목산업기사","토목기사","전산응용기계제도기능사","전산응용토목제도기능사"]', '기능직', '2026-04-06 07:47:09.982748');
