INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (238, '131', '철골공', '연구직 및 공학 기술직', '철골공은 건물이나 다리, 댐 등의 건설에 사용되는 철재 골조나 구조 부품을 제작ㆍ수리하거나 철골재를 이용하여 건축시설물의 골조를 구성하는 일을 담당합니다. 작업지시서에 따라 제작할 철재 골조나 구조 부품을 확인하고 제작에 필요한 재료와 장비 등을 준비합니다. 동력절단기, 화염절단기, 드릴 등의 각종 수공구와 동력 공구를 조작하거나 사용하여 구조용 강재를 절단, 천공, 성형, 제작합니다. 부품을 세우고 정위치시키기 위하여 기중기 운전원에게 신호를 보내고, 렌치, 동력 공구, 리벳 기계 또는 용접 장비를 사용하여 부품을 고정 및 결합시킵니다. 완성된 구조물의 형태와 치수 및 마무리 상태를 검사하고 결함을 수리합니다.', '[]', 35220000, '향후 5년간 철골공의 관련 직업인 경량철골공의 일자리 규모는 현 상태를 유지하거나 다소 …', '["특수용접기능사","용접기능장","용접기사","용접기술사"]', '기능직', '2026-04-06 07:47:10.699959');
