INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (240, '137', '토목공학기술자', '설치·정비·생산직', '토목공학기술자는 국가 기반 시설인 도로, 철도, 교량, 터널, 항만, 상하수도, 댐 등을 계획 및 설계하고 시공합니다. 설비계획 또는 사업계획에 의하여 공사 일정, 설계 일정, 공사 기간 등 단위 공사의 기본 계획을 작성합니다. 토목시설물의 재료를 선택하고 기기의 하중, 풍압 등의 조건에 적합한 구조를 결정하며 색채, 외형 등이 균형과 조화를 이루도록 합니다. 토목 시설물 공사의 각 작업 과정 소요 일정을 판단하고 기전 설비와의 연관관계를 검토하며, 작업의 우선순위, 기후 조건 등을 고려하여 종합 공정표를 작성하고 공정대로 공사가 진행되도록 자재, 인원, 장비의 투입 등 전반적인 공정을 검토·분석합니다. 측량, 조사시험, 설계 등의 용역과 공사 시공에 따른 과업 지시서, 시공품의 중간검사, 설계변경, 준공검사 등과 시설 공사의 감리 업무 등 제반 행정 처리 업무를 수행합니다.', '["건축학과","토목공학과","토목과"]', 51280000, '향후 5년간 토목구조기술자의 일자리 규모는 현 상태를 유지하거나 다소 감소할 전망입니다.…', '["토목산업기사","토목구조기술사","토목시공기술사","토질및기초기술사","토목품질시험기술사","도로및공항기술사","철도기술사","수자원개발기술사","측량및지형공간정보기술사","농어업토목기술사"]', '공학 전문직', '2026-04-06 07:47:11.408778');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (241, '140', '통신장비기사', '건설·채굴직', '통신장비기사는 무선중계기시스템, 유선통신장비, 무선통신장비, 위성통신장비 등의 장비를 유지하고 관리하며 운용합니다. 설치 접수증을 확인하여 설치할 장소와 통신 장비의 종류를 확인합니다. 설계 도면을 검토하여 통신선로를 분리하고 수동 공구, 전기인두 등을 사용하여 전화기, 팩시밀리 등에 통신선로를 연결합니다. 설치가 완료되면 선로시험원에게 연락하여 선로의 장애 유무를 확인합니다. 각종 측정 장비를 사용하여 구내의 통신선로를 점검하기도 하며 파손된 장비를 수리하기도 합니다.', '["스마트정보과","정보통신공학과","정보통신과","컴퓨터공학과","컴퓨터소프트웨어과","컴퓨터응용기계과"]', 39370000, '향후 5년간 통신장비기사의 일자리 규모는 현 상태를 유지할 것으로 전망됩니다. 정보통신산…', '["전기기능사","전기기능장","전기산업기사","전기기사","전자기사","통신기기기능사"]', '기능직', '2026-04-06 07:47:11.764332');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (242, '143', '판금원', '건설·채굴직', '판금원은 철판, 알루미늄, 동, 주석 등과 같은 얇은 금속판을 가공하여 자동차, 선박, 가전제품 등에 사용되는 각종 금속제품을 제작합니다. 도면이나 작업지시서를 검토하여 어떤 제품을 제작해야 하는지 파악하고, 제품의 제작 전개도를 그립니다. 해머, 측정용 공구, 펀치, 절단기, 컴퓨터 등을 이용하여 얇은 금속판으로 필요한 공작물을 제작합니다. 금속판을 절단, 절곡, 천공, 조립, 용접하기 위하여 다양한 수공구 및 동력 공구를 기술적으로 사용합니다. 완성된 제품의 형태, 치수, 마무리 상태 등을 확인하고 이상이나 결함이 발견되면 수리합니다.', '["기계과"]', 37300000, '향후 5년간 판금원 및 판금기조작원의 일자리 규모는 다소 감소할 전망입니다. 판금원의 일…', '["판금제관기능장"]', '기능직', '2026-04-06 07:47:12.123118');
