INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (244, '149', '항공기정비원', '건설·채굴직', '항공기정비원은 항공기의 안전 운행을 위해 항공기의 동체 및 엔진, 계기 등을 조립, 조정, 정비합니다. 고장의 위치, 범위, 정도와 잠재적 불량 상태 등을 확인하기 위하여 시험 측정 기구를 사용하여 각 부분을 진단 및 검사합니다. 고장 부위를 분해하고 수리 또는 교체의 필요성을 판단하기 위하여 명세서와 비교 및 검사하고 작동 상태를 평가합니다. 고장나거나 사용 한계치를 초과한 부품을 교체하고, 연료, 오일 및 기타 보급품을 채웁니다. 설치 또는 수리 부분의 작동 상태를 검사 및 확인합니다.', '["기계공학과","기계과","전기공학과","전기과","전기제어공학과","제어계측공학과","제어계측과","항공우주공학과","항공정비과"]', 40000000, '향후 5년간 항공기정비원의 일자리 규모는 다소 증가할 전망입니다. 국민 생활수준의 향상과…', '["항공기체기술사","항공기관기술사","항공정비사"]', '기능직', '2026-04-06 07:47:12.866505');
