INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (246, '155', '바닥재시공원', '경영·사무·금융·보험직', '바닥재시공원은 각종 타일이나 카펫 등을 설치하여 건물의 내외벽, 바닥, 천장 등을 마무리 또는 장식하는 일을 합니다. 건설 도면을 검토하고 현장 측량 및 의뢰인과의 협의를 통해 필요한 타일이나 카펫의 종류와 형태를 결정합니다. 작업할 표면의 재질에 따라 표면처리 작업을 하고 기준 위치를 결정하며 수직, 수평을 측정합니다. 접합재료를 배합하고 타일을 용도에 따라 절단 및 가공합니다. 접합재를 바르고 균형을 맞추어 타일을 배열하여 붙이고, 타일 표면 및 타일과 타일 사이를 마무리합니다.', '["건축공학과","건축과","토목과","도시건설과"]', 38680000, '향후 5년간 바닥재시공원의 일자리 규모는 현 상태를 유지하거나 다소 증가할 전망입니다. …', '["타일기능사"]', '기능직', '2026-04-06 07:47:13.564274');
