INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (249, '164', '양장사 및 양복사', '연구직 및 공학 기술직', '양장사 및 양복사는 고객의 요구에 따라 여러 디자인의 의복을 제작합니다. 천의 종류, 색상 및 스타일을 상의한 후 고객의 치수를 재고 기록합니다. 고객의 치수대로 본을 제조하여 패턴 모형을 제작합니다. 원단 위에 패턴 모형을 올려놓고 재단하여 시침질로 바느질하거나 재봉틀로 의복의 부분들을 접합합니다. 고객에게 가봉하여 치수 및 디자인을 점검하고 수정하여 의복을 완성합니다.', '["섬유디자인과","섬유디자인학과","의류ㆍ의상학과","패션디자인과"]', 31080000, '향후 5년간 양장 및 양복제조원의 일자리 규모는 감소할 것으로 전망됩니다. 맞춤 양복이나…', '["양장기능사","양복기능사"]', '의복제조 관련직', '2026-04-06 07:47:14.632242');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (250, '167', '소믈리에', '연구직 및 공학 기술직', '소믈리에는 와인을 취급하는 호텔이나 레스토랑, 바, 와인 전문점에서 고객이 주문한 요리에 어울리는 와인을 추천하고 고객의 취향을 파악하여 고객이 원하는 와인을 감정하고 골라 주는 일을 담당합니다. 호텔이나 레스토랑에서 고객이 주문한 요리에 적합한 와인을 추천하고 와인의 맛과 특징, 원산지 등을 설명합니다. 와인의 품목을 선정하고 이에 따른 와인 리스트를 작성하며 와인의 보관과 관리의 책임을 집니다. 와인의 맛을 보고 와인과 어울리는 음식, 장소, 대상 등을 연구합니다.', '["관광경영과","관광경영학과","식품영양학과","식품조리과","외식산업과","외식산업학과","호텔경영과"]', 33150000, '향후 5년간 소믈리에의 일자리 규모는 다소 증가할 전망입니다. 경제성장과 함께 삶의 질이…', '[]', '영업관련 서비스직', '2026-04-06 07:47:14.98341');
