INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (252, '173', '조리사 및 주방장', '연구직 및 공학 기술직', '조리사 및 주방장은 식자재와 조리 도구에 대한 지식을 바탕으로 재료 준비, 식료품 검사와 관리, 세척, 각종 요리 기구를 사용해 알맞은 조리법에 따라 요리하고, 조리된 음식의 맛, 영양 상태 등을 점검합니다. 주문서나 식단 계획표에 따라 재료를 준비하고 세척하며 식료품의 상태를 검사하고 관리합니다. 남은 재료를 손질하여 보관하고 식기, 요리 기구, 장내를 정리합니다. 주방장은 조리사에게 요리와 식재료 가공을 지시 및 감독하고 조리사의 교육과 훈련을 담당하며 주방을 전반적으로 관리합니다.', '["외식조리과","식품영양학과","식품영양과","식품영양학과","식품조리과","외식조리과","전통조리과","조리과학과","호텔조리과"]', 39370000, '향후 5년간 조리사 및 주방장의 일자리 규모는 현 상태를 유지할 전망입니다. 경제성장과 …', '["한식조리기능사","양식조리기능사","일식조리기능사","조리기능장","중식조리기능사","복어조리기능사","한식조리산업기사","중식조리산업기사","일식조리산업기사","양식조리산업기사","복어조리산업기사"]', '조리 관련직', '2026-04-06 07:47:15.678253');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (253, '176', '선장 및 항해사', '건설·채굴직', '선장은 선박 항로, 안전, 해상운송 등의 지식을 바탕으로 화물과 승객 운송을 비롯해, 어로를 위하여 항해하는 선박 내의 여러 활동을 지휘하고 감독하며 조정합니다. 항해사는 선장의 지시에 따라 선박의 항로를 결정하고, 승무원을 지휘하고 감독하여 항해 안전 업무, 선원의 의료 업무, 해상운송 등 갑판 업무의 전반을 관리합니다. 안전한 운항을 위해 항해 목적지, 기후, 거리 등을 확인하고 선박의 조정실, 기관실, 통신실 등을 점검하며 화물의 적재 상태, 식료품, 연료 등을 검사하고 승무원을 확인해 그에 알맞은 업무를 분담하고 지휘합니다. 항해도, 레이더 등을 통해 선박 속도를 파악하여 기후, 해양 상태 등을 바탕으로 선박의 진행을 조절하고 항해 기구, 지도, 차트를 통해 지리적 위치를 파악하며 선박의 항해 기기 및 장비를 유지하고 관리합니다. 화물의 짐을 싣고 내리는 일을 지휘하고 감독하며 갑판 승무원의 활동을 관리하고 조정합니다. 또한 수색 및 구조 서비스를 제공하며 항해 활동을 보조합니다.', '["해양공학과","해양시스템학과","메카트로닉스공학과","항해학과","기계공학과","기계과","항해학과"]', 55940000, '향후 5년간 선장 및 항해사의 일자리 규모는 현 상태를 유지할 전망입니다. 해양수산부의 …', '["기관사","소형선박조종사","운항사","통신사","항해사","해양기술사"]', '일반운전 관련직', '2026-04-06 07:47:16.032405');
