INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (254, '179', '체형관리사', '연구직 및 공학 기술직', '체형관리사는 영양학과 체육학의 지식을 바탕으로 체계적인 운동 방법과 식이요법 등을 이용하여 고객의 체중과 몸매를 종합적으로 관리하는 일을 담당합니다. 고객의 요구와 몸의 특성을 파악하고 신체 균형 상태가 어떤지 기계로 측정하고, 고객에게 적합한 운동 처방, 식이요법, 마인드 컨트롤 등으로 나뉘는 다이어트 프로그램을 설계합니다. 목표 체중이 빠져도 고객이 계속해서 탄력적인 몸매를 갖출 수 있도록 집에서 할 수 있는 간단한 유산소 운동 프로그램 등을 계획하기도 합니다.', '["사회체육학과","체육학과","식품영양학과","외식조리과","조리과학과","사회체육과","식품영양과"]', 31080000, '향후 5년간 체형관리사의 관련 직업인 피부관리사의 일자리 규모는 다소 증가할 전망입니다.…', '["스포츠지도사","영양사"]', '이미용 관련직', '2026-04-06 07:47:16.384916');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (255, '182', '농업기술자', '연구직 및 공학 기술직', '농업기술자는 농업에 대한 지식을 바탕으로 농업의 발전과 농업인의 복지 향상을 도모하기 위하여 농업과학기술의 진흥을 위한 연구와 농촌지도, 농업 관련인에 대한 교육 훈련 업무를 수행합니다. 농업생산력의 증진과 농업인의 생활 개선을 목적으로 하는 농업인 조직을 육성하고, 농촌 청소년과 후계 농업경영인 등 농업 후계 인력을 육성합니다. 농산물의 지속적이고 안정적인 생산을 위해 품질이 좋은 종자를 보급하고, 지역 농업 발전을 위해 기여하며, 현장 기술을 개발해 농업인에게 보급합니다. 농작물 병해충을 막기 위한 방제 정보 확산, 기상재해에 대비한 기술 지도, 농작물의 품질 향상을 위한 지도를 수행합니다.', '["농수산과"]', 42990000, '향후 5년간 농업기술자의 관련 직업인 농학연구원의 일자리 규모는 현 상태를 유지하거나 다…', '["농업기계기사","농업기계산업기사","농화학기술사","유기농업기사","종자기능사","종자기사","종자기술사","종자산업기사","축산기능사","축산기사","축산기술사","축산산업기사","유기농업산업기사","유기농업기능사"]', '환경관련 전문직', '2026-04-06 07:47:16.737453');
