INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (262, '203', '경제학연구원', '연구직 및 공학 기술직', '경제학연구원은 경제학에 대한 지식을 바탕으로 금융, 노동, 재정 등 전문 분야의 연구를 수행합니다. 금융, 노동, 농업 등 전문 분야의 이론적 연구, 실증적 연구를 하기 위한 기초 자료를 수집합니다. 경제 관계 자료를 검토하고 분석하여 연구 결과를 제시하고, 관련 전문가들과 논의하여 정책 제언 등을 도출합니다. 연구가 완료된 자료는 세미나, 토론회 등에서 발표하기도 합니다. 연구의 한계점을 제시하고 이후 보다 나은 연구가 될 수 있도록 추가적인 연구를 수행합니다.', '["금융보험학과","경제학과","농업경제학과"]', 75000000, '향후 5년간 경제학연구원의 일자리 규모는 다소 증가할 전망입니다. 최근 세계경제가 장기 …', '[]', '인문 및 사회과학 관련직', '2026-04-06 07:47:19.228543');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (263, '206', '회계사', '설치·정비·생산직', '회계사는 금융, 회계, 세무학 등의 지식을 바탕으로 개인이나 기업, 공공시설, 정부 기관 등의 경영 상태, 재무 상태, 지급 능력 등의 다양한 재무 보고와 관련하여 상담해주거나 관련 서류를 작성합니다. 대상 기업에서 작성한 기업의 재무와 성과에 관한 보고서인 재무제표가 적절한지 감사하고, 감사 보고서를 작성합니다. 기업의 회계와 결산 업무가 바르게 행해지도록 재무제표를 작성하고, 전표와 장부의 정비 및 개선에 대해 지도하는 업무도 수행합니다. 기업의 재무관리, 판매 정책 등에 대해 효과적인 방안을 제시하고 장단기 경영전략의 수립과 기업합병 등에 대한 경영 자문 업무를 수행하기도 합니다. 납세신고서를 작성하거나 세금에 대한 상담, 지도, 세무 소송 등을 대리하는 세무 업무도 수행합니다.', '["경영학과","경제학과","금융경영과","금융보험학과","세무학과","회계학과"]', 77700000, '향후 5년간 회계사의 일자리 규모는 다소 증가할 전망입니다. 최근 공유경제 시스템 등 복…', '["공인회계사"]', '회계 관련직', '2026-04-06 07:47:19.576056');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (264, '209', '국제회의전문가', '연구직 및 공학 기술직', '국제회의전문가는 국제회의의 기획 및 유치, 준비, 진행 등과 관련된 제반 업무를 조정 및 운영하며, 회의 목표를 설정하고 회의 운영과 관련된 예산을 관리하는 등의 업무도 담당합니다. 국제회의, 전시회 등의 행사를 기획하고 이를 주최하기 위해 관련 업체 와 후원자들을 만나 행사의 크기, 형식, 예산 등에 대해 논의합니다. 전반적인 기획을 한 후, 참가자 등록 업무, 숙박, 행정, 관광, 전시회 등의 국제회의 관련 준비를 진행합니다. 개최할 국제회의를 국내외에 홍보하고, 국제회의의 원활한 진행을 위해 통역사와 관련 종사자를 섭외합니다. 행사 진행에 필요한 지원자들을 모집하고 채용하여 교육하며 지원자들의 활동을 지휘하고 감독합니다.', '["경영학과","관광경영학과"]', 34690000, '향후 5년간 국제회의전문가와 관련 직업인 회의기획자의 일자리 규모는 다소 증가하는 수준이…', '["컨벤션기획사"]', '기획서비스직', '2026-04-06 07:47:19.926863');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (265, '212', '도시 및 교통설계전문가', '설치·정비·생산직', '도시 및 교통설계전문가는 도시설계와 교통체계에 관한 지식을 바탕으로 기존 도시와 특정 단지의 재개발 또는 신도시 건설과 관련하여 도시 및 단지를 계획하고 설계합니다. 건설될 도시와 지역에 관한 자료를 분석하는데, 해당 지역의 인구, 상하수도, 도로 등의 인문환경과 지리적 위치, 기후 등 자연환경을 조사 및 분석하여 향후 그 지역의 발전 및 확장 정도를 추정합니다. 확정된 계획안은 주문처인 자치단체나 건설회사에 제출되어 각계 전문가와 협의하여 결정안으로 확정합니다. 시공에 따라 발생하는 제반 사항에 대한 문제점을 해결하기 위해 현장 점검, 안전진단 등의 업무와 관리 및 감독 업무를 합니다.', '["도시계획학과","도시공학과","지역개발학과"]', 42760000, '향후 5년간 도시 및 교통설계전문가의 관련 직업인 도시계획 및 설계전문가의 일자리 규모는…', '["도시계획기사","도시계획기술사"]', '공학 전문직', '2026-04-06 07:47:20.27921');
