INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (269, '224', '세무사', '설치·정비·생산직', '세무사는 세무에 대한 법률적 지식을 바탕으로 세금에 대한 상담과 자문을 하고, 의뢰인을 대리하여 세무에 대한 각종 서류를 작성하여 세무서에 신고, 신청, 청구하는 등의 일을 합니다. 사업자의 사업 내용에 대한 회계장부 작성을 대행하고 각종 세무신고를 대신합니다. 세무 대리인으로서 신고서, 신청서, 이의신청, 심사 및 심판 청구서 등을 작성하여 과세 관청에 제출합니다. 공개적으로 알리는 땅값인 부동산의 개별공시지가와 주택가격 공시에 대한 이의신청을 대신합니다.', '["경제학과","경영학과","법학과","세무회계학과","회계학과","세무학과","수학과","통계학과"]', 67500000, '향후 5년간 세무사의 자리 규모는 다소 증가할 전망입니다. 기존에는 기업 자체적으로 처리…', '["세무사"]', '회계 관련직', '2026-04-06 07:47:21.691202');
