INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (271, '230', '시장 및 여론조사전문가', '연구직 및 공학 기술직', '시장 및 여론조사전문가는 통계학, 경제학, 사회학 및 심리학 등의 전문 지식을 바탕으로 특정 상품이나 여론 및 선거, TV 시청률 등에 대한 조사와 연구를 실시하고, 조사 결과를 분석하여 보고서로 작성하는 일을 합니다. 의뢰인과 용역의 특성에 따라 조사 계획안을 수립하여 표본추출과 조사 방식, 조사 규모 등을 확정합니다. 개인 또는 전화조사, 인터뷰, 설문조사 등의 진행 과정을 감독합니다. 시장조사전문가는 특정 상품에 대한 소비자의 선호도를 조사하고 분석하여 마케팅 전략 결정에 필요한 기초 자료를 제공합니다. 여론조사전문가는 사회 문제나 선거, 공공정책 개발 및 평가, 계층별 의식, TV 시청률 등에 대한 조사 업무를 수행하고 이에 대한 보고서를 작성합니다.', '["사회학과","심리학과","통계학과"]', 43760000, '향후 5년간 시장 및 여론조사전문가의 일자리 규모는 다소 늘거나 큰 변화가 없을 전망입니…', '["사회조사분석사","소비자전문상담사"]', '금융 및 경영 관련직', '2026-04-06 07:47:22.397964');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (272, '233', '외교관', '설치·정비·생산직', '외교관은 본국을 대표하여 외국에 파견되어 외국과의 교섭을 통해 정치, 경제, 상업적 이익의 보호와 증진을 추구하며, 해외동포와 해외여행을 하는 자국민을 보호합니다. 부임한 나라의 정치적 사건과 상황을 본국에 보고하며, 경제 통상 정보, 생활 정보 등을 수집 및 분석하여 본국의 정부나 기업에 알립니다. 본국을 대신해 본국의 이익과 정책을 옹호하는 교섭을 하고, 본국의 전통 및 문화를 알리는 문화 홍보 활동을 합니다. 본국과 주재국과의 우호 관계를 증진시키고, 양국 간의 경제적, 문화적, 과학적 관계를 발전시키는 역할도 합니다. 부임한 나라에 있는 자국민에게 각종 증명서를 발급해 주고, 출생 및 혼인신고, 여권 발급과 연장 등의 업무를 수행하며 자국민이 위험에 처해 있을 때 그들을 보호합니다.', '["경제학과","국제문화정보학과","국제통상학과","국제학부","독어독문학과","러시아어문학과","법학과","불어불문학과","스페인어학과","아프리카어과","영어과","영어영문학과","영어학과","유럽ㆍ기타어과","일본어과","일어일문학과","정치외교학과","중국어과","중어중문학과","행정학과"]', 67170000, '향후 5년간 외교관의 관련 직업인 정부행정관리자의 고용은 현 상태를 유지하거나 다소 증가…', '[]', '법률 및 사회활동 관련직', '2026-04-06 07:47:22.752095');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (273, '236', '자동차영업원', '설치·정비·생산직', '자동차영업원은 자동차에 대한 지식을 바탕으로 자동차 제조회사에서 생산된 자동차를 고객에게 판매하는 일을 담당합니다. 고객이 원하는 차종과 종류를 파악한 다음, 차량의 가격, 연비, 옵션 사항 등에 대해 설명하고 구매가 이루어질 수 있도록 고객을 설득하여 자동차의 판매 계약을 성사합니다. 자동차 판매 계약을 성사하면, 고객과 자동차의 구매 비용, 인도 일자, 계약조건 등에 대해 논의하며 판매 차량에 대한 보증, 정비 관련 서비스를 제공합니다. 자동차의 제품 정보, 경쟁업체, 시장상황에 대한 정보를 수집하고 분석하여 자동차 영업 및 판매 활동에 활용합니다. 잠재적인 구매 고객을 파악하고 홍보활동을 하며, 기존 고객을 관리합니다.', '["기계공학과","경영학과","금형설계과","기계과","자동차과","자동차정비과"]', 43510000, '향후 5년간 자동차영업원의 일자리 규모는 다소 감소할 전망입니다. 자동차를 렌트하여 이용…', '["자동차정비기사","자동차정비산업기사"]', '영업관련 서비스직', '2026-04-06 07:47:23.101472');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (274, '239', '증권분석가', '연구직 및 공학 기술직', '증권분석가는 통계학, 경제학의 지식을 바탕으로 경제 동향을 파악하여 기업의 재무 상태나 신용도 등의 정보를 토대로 어음, 수표, 채권, 주권, 상품권과 같은 유가증권을 분석합니다. 기업의 실적 예상, 기업의 자금조달 형편의 조사 및 분석, 증권의 가격변동과 수익률 추세 분석 등에 대한 업무를 수행하며 고객에게 유용한 투자 정보를 제공합니다. 주식, 채권 등 유가증권을 발행한 기업의 재무 상태, 유가증권의 가격변동, 수익률, 추세 등을 분석하는 업무를 수행합니다. 위의 분석 결과와 다른 투자회사나 펀드매니저, 투자 고객과의 각종 정보 교환을 바탕으로 신시장 개척, 새로운 투자, 신기술 개발 등 미래에 실현될 증권 관련 사항들을 예측하고 전망합니다. 기업 가치 평가 결과 등을 바탕으로 자산을 운용하거나 고객에게 투자 정보를 제공하고 투자 방향에 대해 자문합니다.', '["경영학과","경제학과","통계학과"]', 62160000, '향후 5년간 증권분석가의 관련 직업인 투자분석가의 일자리 규모는 다소 감소할 전망입니다.…', '[]', '금융 및 경영 관련직', '2026-04-06 07:47:23.453162');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (275, '242', '텔레마케터', '연구직 및 공학 기술직', '텔레마케터는 마케팅에 대한 지식을 바탕으로 각종 상품을 전화 주문을 통해 판매하거나 직접 고객에게 전화를 걸어 상품을 홍보하고 판매하는 일을 담당합니다. 사업체 또는 개인에게 전화를 걸어 제품이나 서비스를 설명하고 구매가 이루어질 수 있도록 영업 활동을 합니다. 고객의 전화에 응대하며 주문받고, 고객의 정보를 데이터베이스에 입력합니다. 고객이 구매한 상품이나 서비스와 관련한 고객의 불편 사항을 접수하기도 하며, 이에 대한 대안이나 해결책을 제시하며 관련 부서에 통보하는 일을 수행합니다.', '["마케팅경영과"]', 28000000, '향후 5년간 텔레마케터의 일자리 규모는 다소 감소할 전망입니다. IT 기술의 발전으로 자…', '["텔레마케팅관리사","소비자전문상담사"]', '영업관련 서비스직', '2026-04-06 07:47:23.801702');
