INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (281, '260', '구성작가', '설치·정비·생산직', '구성작가는 문예 창작과 관련된 지식을 바탕으로 드라마를 제외한 그 외 프로그램들의 기획과 구성, 대본 작성 등에 참여합니다. 교양 및 예능 프로그램의 제작 형식을 기획하고 검토하여 제작에 필요한 자료를 수집하고 정리합니다. 수집한 자료를 기초로 원고를 작성하고 출연진을 섭외하기도 합니다. 방송 연출가와 협의하여 관련 프로그램의 제작에 필요한 정보를 제공합니다.', '["국어국문학과","문예창작과","문예창작학과","신문방송학과"]', 40000000, '향후 5년간 구성작가의 관련 직업인 방송작가의 일자리 규모는 다소 증가할 전망입니다. 방…', '[]', '작가 관련직', '2026-04-06 07:47:25.921054');
