INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (283, '266', '드라마작가', '연구직 및 공학 기술직', '드라마작가는 라디오나 텔레비전 드라마에 필요한 대본을 창작하고 글을 쓰는 일을 담당합니다. 드라마의 주제를 선택하고 내용에 따른 역사적 현실이나 사건의 과정 등을 조사, 분석하여 작품의 줄거리를 구상합니다. 작품의 주제에 따라 등장인물의 성격, 시대적 배경, 장소 등을 결정하며, 드라마를 전개하는 데 필요한 대사와 동작 등을 구상합니다. 완성도 높은 프로그램을 제작하기 위해 드라마작가는 글 쓰는 일 외에 출연자 섭외, 촬영, 편집, 방송 진행에 모두 관여하기도 합니다.', '["국어국문학과","문예창작과","문예창작학과"]', 25000000, '향후 5년간 드라마작가의 일자리는 늘어날 것으로 전망됩니다. 한류열풍과 함께 드라마 콘텐…', '[]', '작가 관련직', '2026-04-06 07:47:26.624631');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (284, '269', '정치학연구원', '설치·정비·생산직', '정치학연구원은 정치제도, 정치운동, 국제정치 상황 등의 연구를 통해 정치 이론을 정립 및 발전시키며 관련 자료를 분석하여 정부, 정당 및 기타 단체에게 정치 관련 자문을 하기도 합니다. 여러 정치 이론과 사상을 바탕으로 실제 행정, 정당제도, 정부와 기업의 관계, 국제사회 관계 등의 제반 문제와 이에 대한 대응 및 해결 방법을 연구합니다. 당대의 정치제도와 정치 관행을 관찰하고 관련 자료들을 분석하여 정부, 정당 및 기타 사회단체에게 정치 관련 자문을 하기도 합니다. 자료를 수집 및 분석하고 정부, 정당 및 기타 단체가 이용하기에 적합한 형식으로 연구 내용과 결론을 발표합니다.', '["정치외교학과"]', 63580000, '향후 5년간 정치학연구원의 일자리 규모는 다소 증가할 것으로 전망됩니다. 급변하는 사회 …', '[]', '인문 및 사회과학 관련직', '2026-04-06 07:47:26.975107');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (285, '272', '언어학연구원', '연구직 및 공학 기술직', '언어학연구원은 언어를 과학적 연구 방법을 통해 특정 언어나 언어 집단의 구조, 변천, 발달 과정을 객관적, 체계적으로 연구합니다. 고어와 현대어에 대한 비교연구를 통해 언어의 기원, 구조, 진화를 연구하고, 언어의 어족과 기원에 따라 고대 및 현대의 불명료한 언어를 분류하고 분석합니다. 특정 언어나 언어집단의 비교연구를 통해 단어와 문장구조의 기원과 변천을 조사하고 연구합니다.', '["언어과학과"]', 70450000, '향후 5년간 언어학연구원의 일자리 규모는 현 상태를 유지하거나 다소 증가할 것으로 전망됩…', '[]', '인문 및 사회과학 관련직', '2026-04-06 07:47:27.322116');
