INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (287, '278', '카피라이터', '설치·정비·생산직', '카피라이터는 기발한 아이디어나 감수성으로 특정 상품이나 서비스가 일반인들에게 쉽게 기억될 수 있는 광고 문구나 문안을 작성하는 일을 담당합니다. 상품 또는 용역에 관한 정보를 얻고 광고 문안의 길이와 형태 등을 토의하기 위해 광고주 및 시장조사 분석가와 협의합니다. 광고의 배경 정보를 얻기 위해 조사와 인터뷰를 수행하고, 광고 문안을 작성하기 위해 상품의 시장조사, 소비자 성향 조사 등의 자료를 검토합니다. 광고전략에 따라 광고 문안, 즉 표제어, 부제어, 본문, 슬로건 등을 작성합니다.', '["광고홍보학과","국어국문학과","문예창작과","문예창작학과"]', 42480000, '향후 10년간 카피라이터를 포함한 작가 및 관련 전문가의 일자리 규모는 다소 증가할 전망…', '[]', '작가 관련직', '2026-04-06 07:47:28.028287');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (288, '281', '개그맨', '설치·정비·생산직', '개그맨은 주로 텔레비전이나 라디오 프로그램에 출연하여 말과 몸짓으로 사람들에게 웃음을 줍니다. 단막극 형식의 짧은 희극을 창작하여 사람들을 즐겁게 할 수 있는 언어와 행동을 합니다. 개인 또는 단체로 대사 연습을 하고, 무대나 드라마에서 사람들을 즐겁게 할 수 있는 연기를 합니다. 방송 출연 전 아이디어 회의를 하고, 프로듀서, 작가와 협력하여 대본을 만들고 연습합니다.', '["방송연예과","연극영화과","연극영화학과"]', 32000000, '향후 5년간 개그맨의 일자리 규모는 현 상태를 유지하거나 다소 감소할 전망입니다. 예능 …', '[]', '연기 관련직', '2026-04-06 07:47:28.382385');
