INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (289, '284', '간판제작원', '설치·정비·생산직', '간판제작원은 네온사인이나 안내표지, 실외 간판 등을 설계 및 제작하여 설치하는 일을 담당합니다. 광고주로부터 주문을 받으면 광고주가 원하는 성격의 광고물에 대해 구체적으로 사용될 디자인, 형태, 기술 등을 기획합니다. 고객의 명세서와 도면에 따라 필요한 재료 및 공구를 준비하고 문자, 상표, 무늬 등을 디자인합니다. 바탕이나 도안에 맞춰 아크릴 등의 재료를 절단하고 색을 칠합니다. 설계 도면에 따라 형광등과 같은 전기 재료를 부착하고 전선을 연결하며, 전동공구를 사용하여 간판을 조립하고 고정합니다.', '["광고디자인학과","공예디자인학과","광고디자인과","산업디자인과","시각디자인과","공업디자인과"]', 35000000, '향후 5년간 간판제작 및 설치원의 일자리 규모는 현 상태를 유지할 전망입니다. 간판 제작…', '["옥외광고사","광고도장기능사"]', '기능직', '2026-04-06 07:47:28.735057');
