INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (292, '293', '메이크업아티스트', '설치·정비·생산직', '메이크업아티스트는 화장을 통해 아름다움을 연출하는 직업으로 분위기와 상황에 맞추어 고객의 메이크업을 담당합니다. 고객의 요구를 파악하고 외모와 얼굴 특성에 따라 화장을 해 줍니다. 메이크업이 끝나면 헤어스타일 및 의상과 조화를 이루는지 점검하고, 화장법에 대해 고객에게 조언하기도 합니다. 메이크업 분야에 따라 뷰티메이크업, 웨딩메이크업, 무대메이크업, 광고메이크업, 포토메이크업, 패션메이크업 등으로 분류됩니다. 뷰티메이크업은 일반인들을 대상으로 졸업식이나 가족사진 촬영, 기념 촬영, 면접이나 오디션을 준비하는 취업 준비생에게 메이크업을 해 주고, 웨딩메이크업은 결혼을 앞둔 신랑, 신부를 대상으로 메이크업을 합니다.', '["메이크업아티스트과","미용과","코디네이션과"]', 32500000, '향후 5년간 메이크업아티스트의 일자리 규모는 다소 증가할 전망입니다. 외모를 아름답게 가…', '["미용사(메이크업)"]', '이미용 관련직', '2026-04-06 07:47:29.820862');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (293, '296', '무대감독', '영업·판매·운전·운송직', '무대감독은 무대 연출에 필요한 촬영, 무대장치, 편집 등의 기술적인 업무를 계획하고 조정합니다. 작품의 예술성을 살리기 위한 무대장치, 조명, 의상, 음향 분야 종사자 등의 역할과 활동을 결정하며, 출연 배우들이 적절한 시기에 등장하도록 조정합니다. 돌발적으로 발생할 수 있는 무대 위의 안전사고에 대한 점검을 하고, 안전사고를 미연에 방지합니다. 공연이 완료되면 무대 종사자들을 지휘하여 모든 물품을 정리 및 보관하고 다음 행사를 준비합니다.', '["미디어영상학과","미술학과","연극영화과","연극영화학과"]', 49730000, '향후 5년간 무대감독의 관련 직업인 무대 및 세트디자이너의 일자리 규모는 다소 증가할 것…', '[]', '예술기획 관련직', '2026-04-06 07:47:30.187746');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (294, '299', '문화재보존원', '연구직 및 공학 기술직', '문화재보존원은 궁궐, 사찰, 미술관, 박물관의 소장품과 같은 문화재의 파손 부위를 복원 및 관리합니다. 손상되거나 훼손된 문화재의 원형을 되살리기 위해 과학적 방법을 사용하며 관련 기술을 연구합니다. 문화재 수리를 담당하는 중요한 사찰이나 유적의 수리 및 보존 공사를 담당합니다. 국가유산수리기술자, 국가유산수리기능자, 보존과학기술자 및 기능자 등으로 구분되며 국가유산수리기술자는 각 분야에 대한 기술을 자문하고, 각종 공사와 국가유산수리기능자를 관리 및 감독합니다. 보존과학기술자 및 기능자는 문화재의 손실 원인을 과학적으로 규명하여 파손을 적합한 방법으로 보존 처리합니다.', '["고고학과","문화재보존학과","사학과","역사교육과"]', 38000000, '향후 5년간 문화재보존원의 일자리 규모는 현 상태를 유지할 전망입니다. 국민소득이 향상되…', '["국가유산수리기능자","국가유산수리기술자"]', '인문 및 사회과학 관련직', '2026-04-06 07:47:30.540026');
