INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (298, '311', '사진인화 및 현상관련조작원', '설치·정비·생산직', '사진인화 및 현상관련조작원은 사진필름 및 인화지 제조기를 조작하며, 사진필름을 가공하고 인화합니다. 사진판 코팅 및 보강용 장비를 조작합니다. 음화 또는 투명한 양화를 얻기 위하여 천연색 및 흑백필름을 가공하는 장비를 조작합니다. 흑백 및 컬러 사진 인화용, 확대용, 축소용 장비를 조작합니다. 현상된 필름의 결함을 찾아내고 수정해야 하는 부분을 교정합니다.', '["방송영상과","사진영상학과"]', 35000000, '향후 5년간 사진인화 및 현상관련조작원의 일자리 규모는 다소 감소할 전망입니다. 디지털카…', '["사진기능사"]', '기능직', '2026-04-06 07:47:31.965077');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (299, '314', '스턴트맨', '연구직 및 공학 기술직', '스턴트맨은 영화나 텔레비전 드라마에 출연하여 무술 연기를 합니다. 연극, 영화, 드라마 등에서 주연배우를 대신하여 춤, 수영, 스케이팅, 승마 등의 특수한 기술을 요하는 역할이나 연기를 대신합니다. 각 장면에서 연출되는 특정 상황에 맞는 복장이나 분장을 하고 감독의 지시에 따라 액션 연기를 합니다. 주연 배우를 대신하여 고공 낙하, 자동차나 말에서 뛰어내리기, 폭발 직전의 건물에서 뛰어나오기 등의 위험한 연기를 합니다.', '["방송연예과","연극영화과","연극영화학과","영화과"]', 40000000, '향후 5년간 스턴트맨의 일자리 규모는 현 상태를 유지할 전망입니다. 일상생활에서 여가문화…', '[]', '연기 관련직', '2026-04-06 07:47:32.31734');
