INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (300, '317', '연주가', '설치·정비·생산직', '연주가는 독주자 또는 오케스트라 및 악단의 일원으로 악기를 연주합니다. 현악기, 관악기, 건반악기, 타악기 중 특정 악기의 연주를 전문으로 합니다. 음악과 악보를 연구하고 바람직한 음악적 효과를 내기 위하여 각 요소를 종합하며, 지휘자 및 다른 연주자들과 토론하고 협연합니다. 음반 제작을 위해 녹음에 참여하며, 악기를 조율하고 악보를 직접 편곡하기도 합니다. 가수들의 노래나 다른 기악의 연주를 반주하는 경우에는 반주자가 될 수도 있으며 발레, 오페라 등의 공연에서 배경음악을 담당하기도 합니다.', '["관현악과","기악과","성악과","음악과","음악학과","작곡과","피아노학과"]', 30000000, '향후 5년간 연주가의 일자리 규모는 현 상태를 유지할 전망입니다. 여가 활동이 증가하고,…', '[]', '음악 관련직', '2026-04-06 07:47:32.71907');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (301, '320', '연극연출가', '설치·정비·생산직', '연극연출가는 한 편의 연극을 연출하기 위해 희곡 작품의 주제, 성격 등을 분석하고, 연기자들과 스텝들을 지휘 및 감독합니다. 희곡 작품을 검토하고 제작자와의 협의를 통해 연극의 주요 배역을 선정합니다. 연기자들의 연기를 지도하여 연기자들이 자신의 배역을 잘 표현해 낼 수 있도록 합니다. 연극의 주제에 맞춰 의상, 음향, 특수 효과, 안무 등에 관련된 사항을 결정하고 무대감독과 협의하여 연극 무대를 구성합니다.', '["연극영화과","연극영화학과"]', 22000000, '향후 5년간 연극연출가의 일자리 규모는 다소 증가할 전망입니다. 삶의 질 향상, 여가 문…', '[]', '예술기획 관련직', '2026-04-06 07:47:33.071082');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (302, '323', '영화기획자', '경영·사무·금융·보험직', '영화기획자는 영화의 기획에서부터 개봉에 이르는 전 과정에 대한 기획과 관리를 담당합니다. 새로운 영화 소재의 발굴을 위해 소설 또는 대본(시나리오)을 검토하고 흥행에 성공할 수 있는 작품을 선정합니다. 영화의 기본 시나리오와 인력, 소요 비용, 제작 기간 등에 대한 기획안을 작성합니다. 기획안이 통과되어 영화화하기로 결정이 되면, 영화감독, 출연 배우, 스태프 등을 섭외합니다. 영화의 촬영이 완료된 후에는, 영화시장의 특성과 유통구조를 잘 파악하여 개봉 시기와 개봉 영화관, 영화의 홍보 등의 계획 및 실행 업무를 담당합니다.', '["연극영화과","연극영화학과"]', 45790000, '향후 5년간 영화기획자의 관련 직업인 공연기획자의 고용은 다소 증가할 것으로 전망됩니다.…', '[]', '예술기획 관련직', '2026-04-06 07:47:33.431741');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (303, '326', '인테리어디자이너', '미용·여행·숙박·음식·경비·청소직', '인테리어디자이너는 주택, 사무실, 상가 건물의 내부 환경을 기능과 용도에 맞게 설계하고 장식합니다. 내부 환경이 장식에 영향을 미치는 요인을 조사 및 결정하기 위하여 고객과 협의합니다. 건물의 목적, 기능, 예산, 건축 형태 등 여러 특성을 파악하여 디자인 콘셉트를 정하고 세부 일정 및 계획을 수립합니다. 공간 구조, 가구나 시설의 배치 및 이용, 색상 등 구체적인 계획에 대하여 고객과 협의하고, 동선 계획과 색채 계획, 조명 계획 등을 세웁니다. 디자인이 완성되면 세부 도면을 작성하여 시공업자에게 전달하고 경우에 따라서는 시공 작업을 감독하기도 합니다.', '["건축공학과","공예과","공예학과","산업디자인과","산업디자인학과","시각디자인과","시각디자인학과","환경디자인과","환경디자인학과"]', 38670000, '향후 5년간 실내장식디자이너의 일자리 규모는 현 상태를 유지할 전망입니다. 인테리어디자인…', '["실내건축기능사","실내건축기사","실내건축산업기사"]', '디자인 관련직', '2026-04-06 07:47:33.77839');
