INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (305, '332', '제품디자이너', '보건·의료직', '제품디자이너는 우리의 일상생활에 필요한 각종 제품을 디자인합니다. 디자인 의뢰가 들어오면, 시장조사를 통해 소비자의 취향과 욕구, 유행을 분석하고 디자인 콘셉트를 정합니다. 설계도를 바탕으로 점토, 나무, 종이 등으로 모형 제작 후 개조, 수정 작업을 거쳐 설계 도면을 만듭니다. 시안으로 여러 디자인을 만든 후 몇 번의 수정 작업을 거쳐 최종 디자인을 결정합니다. 기술적인 문제가 없는지 확인하고, 특히 디자인에 따라 성능, 부품, 자재를 자유롭게 이용할 수 있는지 등에 대해 전에 충분히 협의합니다.', '["공업디자인과","공업디자인학과","공예과","공예디자인학과","산업디자인과","산업디자인학과","시각디자인과","시각디자인학과","제품디자인과","패션디자인과"]', 38000000, '향후 5년간 제품디자이너의 일자리 규모는 현 상태를 유지하거나 다소 증가할 전망입니다. …', '["제품디자인기사","제품디자인기술사","제품디자인산업기사","제품응용모델링기능사"]', '디자인 관련직', '2026-04-06 07:47:34.493837');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (306, '335', '지휘자', '설치·정비·생산직', '지휘자는 관악기, 현악기, 타악기 등을 연주하는 관현악단을 지휘하고, 화음을 연출하기 위해 합창단을 지휘하는 일을 담당합니다. 연주를 심사하여 기악 연주자를 선정하고, 계획된 공연에 적합하고 연주자들의 재능과 능력에 알맞은 연주곡을 선정합니다. 각 악기의 화음이 균형과 조화를 이룰 수 있도록 연주자들을 적절히 배치합니다. 음악 작품을 해석하여 음색과 화음이 조화되어 음악적 효과를 낼 수 있도록 연주자들을 지휘합니다. 악보를 편곡하기도 하고 지방 또는 해외 연주 계획을 수립하기도 합니다.', '["관현악과","기악과","음악학과","작곡과"]', 27000000, '향후 5년간 지휘자의 일자리 규모는 현 상태를 유지할 전망입니다. 문화에 대한 국민의 욕…', '[]', '음악 관련직', '2026-04-06 07:47:34.843537');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (307, '338', '출판물기획전문가', '설치·정비·생산직', '출판물기획전문가는 독자가 원하는 출판물의 내용과 출판 시장 동향 등을 파악합니다. 작가 섭외, 출판물 영업 전략 등 출판물 기획 및 제작에 관련된 모든 일을 담당합니다. 다양한 조사와 연구를 수행하며, 다른 출판물과의 차별성과 최근 경향을 고려해 세부적인 기획안을 작성합니다. 출판물에 적합한 작가를 섭외하고 집필된 원고를 검토합니다. 내용상 필요한 그림이나 삽화, 사진 등을 수록하기 위해 미술가나 사진가에게 작업을 요청합니다.', '["국어국문학과","미디어출판과"]', 39680000, '향후 5년간 출판물기획전문가의 일자리 규모는 감소할 전망입니다. 출판산업은 종이책 중심의…', '[]', '예술기획 관련직', '2026-04-06 07:47:35.195101');
