INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (309, '344', '패션디자이너', '농림어업직', '패션디자이너는 천(직물), 가죽, 비닐 등 여러 가지 소재로 남성복, 여성복, 아동복, 속옷 등 옷을 디자인합니다. 제품이 나오기 약 6개월 전부터 국내외 패션 흐름 등을 파악하고, 유행 경향, 소재, 색 등의 조화 등에 관련된 자료를 종합적으로 분석하여 새로운 패션 디자인을 기획합니다. 기획한 자료를 바탕으로 소비자의 성별과 연령에 맞는 새로운 의상을 디자인합니다. 디자이너가 디자인한 옷은 견본 의상으로 제작하고, 견본 의상을 실제 입어보면서 옷의 착용감 등을 파악하여 디자인을 수정하며 판매할 수 있는 옷으로 제작을 합니다.', '["의류ㆍ의상학과","패션디자인과","시각디자인과","공예학과","산업디자인과","섬유디자인과","공예과","섬유공학과","시각디자인과","코디네이션과","산업디자인학과"]', 36130000, '향후 5년간 패션디자이너의 관련 직업인 패션소품디자이너의 일자리는 현 상태를 유지할 전망…', '["패션디자인산업기사","섬유디자인산업기사"]', '디자인 관련직', '2026-04-06 07:47:35.89166');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (310, '347', '악기수리원 및 조율사', '설치·정비·생산직', '악기수리원 및 조율사는 각종 악기의 파손된 부위를 수리하거나 조율합니다. 악기수리원은 악기를 연주 등을 통해 소리를 점검하여 파손된 부위를 확인한 후 결함이 있는 부분을 수리하고 결함이 있는 부품을 제거하거나 교체합니다. 조율사는 악기의 수리, 음색을 바로잡는 정음 등의 작업을 담당합니다.', '["관현악과","음악과","피아노학과","음향제작과","기악과"]', 38150000, '향후 5년간 악기수리원 및 조율사의 일자리는 현 상태를 유지할 전망입니다. 국내 악기시장…', '["피아노조율기능사","피아노조율산업기사"]', '악기 관련직', '2026-04-06 07:47:36.365066');
