INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (312, '353', '간병인', '미용·여행·숙박·음식·경비·청소직', '간병인은 병원, 요양소, 산후조리원 등에서 환자의 보호자를 대신하여 환자를 간호하고 돌보는 일을 합니다. 움직임이 불편한 환자를 목욕시키고, 환자가 이동할 때 휠체어를 밀어 주거나 함께 이동합니다. 환자의 체온, 맥박, 호흡수 등을 측정하고 기록하며, 환자가 먹는 음식 및 음료의 양과 내용을 체크하고, 필요에 따라서 환자에게 음식을 먹여 줍니다. 병실의 청소를 담당하는 등 환자 주변의 위생 상태를 관리하고, 환자의 안정을 위해 말벗이 되어 주기도 합니다. 환자에게 약을 먹여 주고 확인하는 일, 의사 회진 시 환자 상태에 대한 경과 보고, 증상 관찰 등의 일을 수행합니다.', '[]', 22790000, '향후 5년간 간병인의 관련 직업인 간병인의 일자리 규모는 증가할 전망입니다. 사회가 고령…', '["요양보호사"]', '보건의료 관련 서비스직', '2026-04-06 07:47:37.079826');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (313, '356', '청소원', '예술·디자인·방송·스포츠직', '청소원은 건물의 내부와 외부, 거리 및 기타 공공장소, 운송장비(자동차, 항공기, 선박 등) 등의 청소와 관련된 업무를 담당합니다. 건물청소원은 빌딩, 병원, 상가, 아파트, 호텔, 미술관 등의 내부 및 외부를 청소합니다. 환경미화원은 거리, 공원 등의 공공장소를 청소합니다. 운송장비 청소원은 승용차, 버스, 항공기, 선박, 기관차 등의 운송장비의 외부를 세척하거나 내부의 쓰레기를 청소합니다.', '[]', 22000000, '향후 5년간 청소원의 일자리 규모는 현 상태를 유지할 전망입니다. 깨끗한 도시 환경을 유…', '[]', '일반 서비스직', '2026-04-06 07:47:37.42658');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (314, '359', '경찰관', '미용·여행·숙박·음식·경비·청소직', '경찰관은 국민의 생명과 재산을 보호하는 역할을 합니다. 범죄 수사를 통해 범인을 잡고, 범죄 예방을 위한 순찰 등 안전한 사회를 만들기 위해 노력합니다. 해킹, 인터넷 사기, 사이버명예훼손 등 사이버 공간의 안전을 위협하는 사이버범죄를 수사합니다. 교통을 단속하고 교통사고 예방을 위한 계획을 세우는 등 교통안전을 위한 일을 합니다. 중요 인사의 경호, 비상 훈련 실시 등 국가 안전을 위한 업무를 수행합니다.', '["법학과","해양경찰학과","경찰행정학과"]', 39000000, '향후 5년간 경찰관의 일자리 규모는 다소 증가할 것으로 전망됩니다. 우리나라는 2015년…', '["자동차운전면허"]', '안전 관련직', '2026-04-06 07:47:37.777842');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (315, '362', '일반공무원', '미용·여행·숙박·음식·경비·청소직', '일반공무원은 국가 또는 공공기관에 소속되어 행정 업무와 민원 업무 등 각종 업무를 수행합니다. 법령과 업무처리 규정에 따라 관련 업무를 계획하고 시행합니다. 정부 고유의 행정 업무인 주민등록, 출생, 사망, 혼인 등과 관련된 서류 접수 및 발급 등의 업무를 수행하거나, 각종 승인이나 검사, 허가 등 정부 행정 집행과 관련된 업무를 수행합니다. 국민과 직간접적으로 연관되어 있으며, 기술적인 업무, 연구, 농어촌 지도 업무, 일반 행정 등을 담당합니다.', '["경영학과","사회복지학과","법학과","행정학과","회계학과","경제학과"]', 36260000, '향후 5년간 일반공무원의 관련 직업인 입법공무원의 일자리 규모는 현 상태를 유지할 전망입…', '[]', '사무 관련직', '2026-04-06 07:47:38.134055');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (316, '365', '독서지도사', '연구직 및 공학 기술직', '초등학생, 중학생, 고등학생을 대상으로 독서교육 프로그램을 개발하고 교육하고 평가합니다. 학생들에게 독서지도를 하며, 독서교육에 대한 학습 상담 및 교육적 자문을 합니다. 학생들에게 독서 전, 독서 중, 도서 후 활동에 필요한 기술 및 방법을 가르치고, 독후감 쓰기 및 자유로운 독서 토론을 지도합니다. 학생들의 독서 습관에 대해 부모나 학생들과 상담을 합니다.', '["국어국문학과","국어교육과"]', 40000000, '향후 5년간 독서지도사의 관련 직업인 문리학원강사의 고용은 현 상태를 유지하거나 다소 감…', '[]', '교육관련 서비스직', '2026-04-06 07:47:38.49225');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (317, '368', '곡식작물재배자', '농림어업직', NULL, '[]', 30000000, NULL, '[]', '농생명산업 관련직', '2026-04-06 07:47:38.837128');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (318, '371', '택배원', '예술·디자인·방송·스포츠직', '택배원은 고객이 주문한 상품이나 구매한 상품 등 각종 물품을 고객이 원하는 곳까지 운반하는 일을 합니다. 고객이 주문하거나 구매한 상품을 받아 차량을 이용하여 고객이 원하는 장소에 배달합니다. 물류 관련 사무원으로부터 배송물의 목록, 품목, 수량, 장소 등이 적힌 출고장과 배송장을 수령하고 전산시스템에 입력합니다. 물품을 고객에게 전달하고, 배송장의 바코드를 이용하여 전산시스템에 배송 완료 내역을 입력합니다. 차량 사고, 배달 지연, 물품 파손 등 배송 중 이상이 발생하게 된 경우 관련 규정에 따라 조치합니다.', '[]', 37650000, '향후 5년간 택배원의 일자리 규모는 다소 늘어날 전망입니다. 온라인 소비가 일반화되며 택…', '["자동차운전면허"]', '일반운전 관련직', '2026-04-06 07:47:39.205198');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (486, '875', '호스피스전문간호사', '보건·의료직', NULL, '[]', 30000000, NULL, '[]', '보건의료 관련 서비스직', '2026-04-06 07:48:38.82942');
