INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (319, '374', '변리사', '농림어업직', '변리사는 새로운 기술의 발명이나 디자인, 상표 등의 특허권 취득을 위한 법률적인 부분과 기술적인 부분에 대한 상담 및 지원을 제공합니다. 특허권을 얻고자 하는 대상의 설계도, 제품 등을 조사 및 검토하고 유사 제품의 특허권을 조사합니다. 기존 다른 산업재산권의 침해 여부, 발명이나 상표 등이 비슷한지에 대한 감정을 합니다. 특허등록을 위한 문서를 작성하고, 의뢰인과 검토 후 특허권을 출원, 청구합니다. 소유권 권리 분쟁이나 특허 발급 거부 등 특허 분쟁에 대한 소송을 대리합니다.', '["행정학과","정보통신공학과","산업공학과","화학과","광학공학과","기계공학과","전기공학과","법학과","물리학과","생물학과","제어계측공학과"]', 65080000, '향후 5년간 변리사의 일자리 규모는 늘어날 것으로 전망됩니다. 지식재산을 둘러싼 기업 간…', '["변리사"]', '법률 및 사회활동 관련직', '2026-04-06 07:47:39.562615');
