INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (321, '380', '상담전문가', '설치·정비·생산직', '상담전문가는 성격, 정서, 관계, 진로 및 정신적 증상 등에 대해서 어려움을 겪고 있거나 그러한 어려움을 해결하고자 하는 사람에게 심리검사, 상담 프로그램 등을 활용하여 문제 해결을 돕고 지원합니다. 성격, 정서, 관계, 진로 등에 대해 상담을 요청하는 사람(내담자)과의 대화를 통해 문제가 무엇인지 알아봅니다. 표준화된 심리검사를 실시하고, 상담을 통해 내담자의 내면을 심층적으로 탐색하여 그 결과를 분석합니다. 분석한 결과를 토대로 개인상담, 집단상담, 자기 성장 프로그램, 대인관계 향상 프로그램 등 다양한 방식으로 앞으로의 바람직한 방향을 함께 찾습니다. 학교 상담사의 경우 학생들을 대상으로 학교 외 생활에서 경험하는 다양한 문제들에 대해 상담을 진행합니다.', '["가족복지과","사회복지과","사회복지상담과","사회복지학과","교육학과","아동학과","아동복지학과","심리학과","청소년지도학과","아동복지과","노인복지학과"]', 31080000, '향후 5년간 상담전문가의 일자리 규모는 증가할 전망입니다. 사회가 빠르게 변화하면서 심각…', '["전문상담교사","청소년상담사","임상심리사"]', '사회서비스직', '2026-04-06 07:47:40.296132');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (322, '383', '우편물집배원', '농림어업직', '우편물집배원은 우편물을 표시된 주소에 전달하는 일을 담당합니다. 우체국 관할 구역에 있는 우체통 안의 우편물을 수집하여 우체국에 전달하고, 배달할 우편물을 담당 구역 및 배달 순서로 구분합니다. 지정된 순서에 따라 오토바이 또는 차량으로 해당 주소지에 전달하고, 등기 소포 등의 우편물은 전달한 사람에게 직접 전달하여 확인을 받습니다. 주소가 분명하지 않거나 받는 사람이 확실하지 않아 전달하지 못한 우편물은 전달하지 못한 이유를 기록하여 사고우편물 처리원에게 인수인계합니다.', '[]', 35110000, '향후 5년간 우편물집배원의 일자리 규모는 현 상태를 유지할 전망입니다. 인터넷 및 모바일…', '["자동차운전면허"]', '안전 관련직', '2026-04-06 07:47:40.653274');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (323, '386', '언어치료사', '연구직 및 공학 기술직', '언어치료사는 언어장애의 증상과 원인을 진단하고, 이에 대한 치료 계획을 세워 환자를 치료합니다. 환자의 발음, 지능 및 어휘력 측정을 위하여 각종 검사를 실시하여 조음장애, 언어 지체, 실어증, 음성 장애 등 언어장애의 원인과 유형 및 심각한 정도를 진단합니다. 사회관계 형성 및 유지에 필요한 언어 사용 능력을 증진시키기 위해 단어, 글자, 그림 카드, 퍼즐 등 도구를 사용하거나 및 집단적 치료를 수행하기도 합니다. 언어장애 환자와 환자 기족 및 담당 교사를 대상으로 상담 또는 지도 활동을 합니다. 언어장애의 치료 기술 개발을 위한 전문적인 연구를 수행하기도 합니다.', '["언어치료학과","특수교육학과"]', 31080000, '향후 5년간 언어치료사의 일자리 규모는 증가할 전망입니다. 언어장애에 대한 인식이 달라지…', '["언어재활사"]', '보건의료 관련 서비스직', '2026-04-06 07:47:41.016428');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (324, '389', '해양수산기술자', '연구직 및 공학 기술직', NULL, '[]', 50000000, NULL, '[]', '공학 전문직', '2026-04-06 07:47:41.364242');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (325, '392', '스포츠트레이너', '경영·사무·금융·보험직', '스포츠트레이너는 운동선수들의 건강상태를 확인하고 선수들이 경기에서 최상의 컨디션을 발휘할 수 있도록 조언하고 훈련을 시킵니다. 운동감독 및 코치와의 협의를 통해 운동 종목, 선수들의 포지션과 선수 개인의 기량에 따라 필요한 운동량을 결정하고 근육 단련을 위해 규칙적인 운동과 식이요법을 지시합니다. 부상을 당한 선수들에게 응급 조치를 하고, 의사의 진단 결과에 따라 재활훈련을 계획하고 실시합니다. 선수들의 부상을 예방하기 위해 마사지를 해 주고 안전교육을 실시합니다.', '["사회체육학과","사회체육과","물리치료과","체육학과","물리치료학과","체육교육과"]', 36000000, '향후 5년간 스포츠트레이너의 일자리 규모는 늘어날 전망입니다. 스포츠트레이너는 비단 국가…', '["스포츠지도사","건강운동관리사"]', '운동 관련직', '2026-04-06 07:47:41.714732');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (326, '395', '유치원교사', '교육·법률·사회복지·경찰·소방직 및 군인', '유치원교사는 학교에 입학하기 전인 아동에게 필요한 교육을 합니다. 아동들의 지적, 정서적, 사회적 발달을 위한 교육활동을 합니다. 유아들이 직접 참여할 수 있는 다양한 수업 방법(발표, 토의, 조사, 견학, 발표회 등)을 계획하고 활용하여 지도합니다. 등원, 정리 정돈, 평가, 집단활동(토의, 게임, 요리 등) 및 실외활동 진행, 급식 및 간식 제공, 하원,교육과정의 계획 및 운영 등의 일을 합니다. 학부모를 대상으로 유아 발달에 협조할 수 있는 부모교육, 가정통신문 발송, 출결 사항 관리 등 행정 업무도 하고, 아동들의 유치원 생활, 학습 능력 등 성장 문제에 대하여 상담합니다.', '["유아교육과","유아교육학과"]', 30000000, '향후 10년간 유치원교사의 일자리 규모는 현 상태를 유지하는 수준이 될 것으로 전망됩니다…', '["정교사"]', '교육관련 서비스직', '2026-04-06 07:47:42.088138');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (327, '398', '임상심리사', '영업·판매·운전·운송직', '임상심리사는 정신적인 어려움이 있는 사람에게 심리 평가를 실시하며 몸과 마음의 건강 증진을 돕습니다. 정신 건강에 어려움을 경험하고 있는 사람(환자 및 내담자)에 대한 정확한 진단을 위하여 인지능력, 성격, 정서, 신경 심리 등에 대해 검사를 실시하고 평가합니다. 내담자가 겪는 어려움의 원인을 분석하고 치료 방법, 기간, 강도 등 적절한 치료 계획을 수립합니다. 심리 평가 결과와 치료 경과에 대하여 정신과의사 등 정신보건 관련 전문가들과 공유하고 치료 진행 사항 등에 대해 논의합니다. 정신건강과 관련된 프로그램을 개발하고 실시하며, 심리치료에 관한 연구를 수행합니다.', '["심리학과"]', 39940000, '향후 5년간 임상심리사의 일자리 규모는 늘어나는 수준이 될 것으로 전망됩니다. 최근 사회…', '["정신건강임상심리사","임상심리사"]', '보건의료 관련 서비스직', '2026-04-06 07:47:42.447012');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (328, '401', '작업치료사', '경영·사무·금융·보험직', '작업치료사는 신체적 또는 장애를 입은 환자가 독립적으로 일상생활을 할 수 있도록 치료 활동을 합니다. 환자의 병력을 근거로 인지 지각 능력, 운동능력, 손 기능 능력 등을 평가하고, 평가에 의거하여 치료 계획을 수립합니다. 환자의 신체적 또는 정신적 장애를 회복시키기 위해 감각 지각 활동 훈련, 인지 재활치료, 일상생활 훈련, 직업 재활훈련 등 작업요법적 치료를 계획하고 실시합니다. 치료 과정, 훈련 실시 내용, 결과 등을 작성하여 의료진과 함께 평가합니다. 질병 자체보다는 질병으로 인한 기능 저하에 관심을 두고 그에 적합한 방법을 선택하여 치료합니다.', '["작업치료과","작업치료학과"]', 33670000, '향후 5년간 작업치료사의 일자리 규모는 늘어날 것으로 보입니다. 최근에 사회복지 제도가 …', '["작업치료사"]', '보건의료 관련 서비스직', '2026-04-06 07:47:42.804885');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (329, '404', '전화교환원', '연구직 및 공학 기술직', '전화교환원은 시내, 시외 및 국제 간 혹은 회사 내부의 전화 통화를 연결하는 일을 담당합니다. 고객이 문의하는 상호 또는 인명을 듣고 컴퓨터에 연결된 단말기를 조작하여 번호를 안내하거나 통화를 연결하는 일을 합니다. 숙박업소의 전화교환원은 호텔에 투숙한 고객의 방으로 전화를 연결해 주며, 고객의 요청에 따라 모닝콜을 하기도 합니다.', '[]', 28000000, '향후 5년간 전화교환원의 관련 직업인 안내·접수원의 일자리 규모는 다소 줄어들 전망입니다…', '[]', '일반 서비스직', '2026-04-06 07:47:43.154282');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (330, '407', '직업군인', '경영·사무·금융·보험직', '직업군인은 국가의 안전보장과 국민의 생명 및 재산을 보호하기 위한 일을 합니다. 지휘관으로서 일반 병사를 지휘, 통솔하거나 혹은 참모로서 지휘관을 보좌하여 정보, 작전, 인사, 군수 등 전문 업무를 수행합니다. 외부의 모든 군사적 위협으로부터 국가를 보호하고 전쟁이 일어나지 않도록 하며 군사적 긴장을 낮추어 평화와 안정을 위한 일을 합니다. 남북한 간의 군사분계선 감시 및 관리, 해안선 및 국가 중요 시설에 대한 경계와 수색 정찰을 합니다. 국가 기간산업의 보호, 환경보호 활동 지원, 구난구조, 테러 방지, 분쟁지역에 대한 평화유지 활동, 해상 수송로 보호 등의 일을 합니다.', '["부사관과","군사학과"]', 36000000, '향후 5년간 직업군인의 관련 직업인 위관급 장교의 일자리 규모는 현 상태를 유지할 전망입…', '[]', '안전 관련직', '2026-04-06 07:47:43.509444');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (331, '410', '초등학교교사', '경영·사무·금융·보험직', '초등학교 교사는 초등학교에서 학생들을 대상으로 수업 지도, 학급 운영, 생활지도 등을 담당합니다. 학교의 교육 계획과 수업일수 등을 고려하여 각 교과목의 학습 계획안을 작성하고 이에 맞는 교재 연구 및 교수학습 자료를 준비합니다. 학습 과제물을 검사하고 시험을 출제하고 평가하는 등의 학습평가를 실시합니다. 학생들이 원만한 친구 관계를 맺고 다른 사람과 더불어 살 수 있도록 지도하고, 안전사고 및 폭력의 예방, 기본 생활 습관 등과 관련된 생활지도를 하며, 학생과 학부모를 대상으로 상담을 합니다. 학생들의 전학, 입학, 출석, 생활기록부 등을 관리하고, 가정통신문 작성 등 학사 업무를 하며, 학교 교육과정의 편성 및 운영에 참여하고 교직원 회의에 참석하는 등 학교 업무를 수행합니다.', '["초등교육과"]', 40720000, '향후 5년간 초등학교교사의 일자리 규모는 다소 줄어들 전망입니다. 저출산 문제의 심화에 …', '["정교사"]', '교육관련 서비스직', '2026-04-06 07:47:43.8696');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (332, '413', '특수교사', '경영·사무·금융·보험직', '특수교사는 신체적, 정신적 장애를 겪고 있는 학생에게 유치원, 초등학교, 중학교, 고등학교에 준하는 교육과 생활에 필요한 지식 및 기능을 가르칩니다. 장애에 따라 시각장애, 청각장애, 발달장애, 지체부자유, 정서장애로 구분되며, 학생들이 겪는 어려움에 맞추어 교육을 합니다. 장애 학생의 장애 정도와 발달 상황 등을 고려하여 적절한 교재와 교육 방법을 활용해 학습지도를 합니다. 점심 식사 및 등하교 지도, 옷 입기와 벗기, 몸단장, 손 씻기 등 학생들의 생활지도 및 인성 지도를 담당합니다.', '["특수교육학과"]', 38330000, '향후 5년간 특수교사의 관련 직업인 특수학교 교사의 일자리 규모는 현 상태를 유지하거나 …', '["정교사"]', '인문계 교육 관련직', '2026-04-06 07:47:44.224246');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (333, '416', '피부관리사', '경영·사무·금융·보험직', '피부관리사는 고객의 얼굴부터 발끝까지 신체의 모든 피부 상태를 아름답고 건강하게 관리해주는 일을 합니다. 고객과의 상담을 통해 피부 유형을 파악하고, 적합한 화장품의 종류나 피부 관리법을 소개합니다. 피부의 모공 관리, 여드름 관리, 눈썹 관리, 주름 및 피부 처짐 방지, 노화 방지, 손상된 피부 회복 등 피부 개선 프로그램을 계획하고 관리합니다. 피부 관리 서비스를 수행하면서 고객의 피부 유형에 맞는 화장품과 미용 기구, 마사지, 팩 등을 이용해 피부를 탄력 있고 청결하게 관리합니다. 피부 관리는 마사지와 피부 관리 방법 교육, 기초화장품과 영양 크림을 바르는 것을 포함합니다. 얼굴 마사지뿐만 아니라 몸 전체 피부를 관리해 주기도 하고 손상된 피부를 회복시키는 일도 합니다.', '["피부미용과"]', 31080000, '향후 5년간 피부관리사의 일자리 규모는 다소 증가할 전망입니다. 최근에는 정기적으로 피부…', '["미용사(피부)"]', '이미용 관련직', '2026-04-06 07:47:44.575617');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (334, '419', '홍보도우미', '경영·사무·금융·보험직', '홍보도우미는 고객이 상품이나 서비스의 구매하거나 시설 이용을 하도록 판촉물을 배포하거나 춤, 노래, 게임 등을 이용하여 상품과 서비스를 홍보하는 일을 합니다. 전시회, 판촉 행사, 신제품 설명회 등이 시작하기 전에 상품이나 서비스, 시설의 특징, 홍보 방법 등에 대한 교육을 받고 관련 내용을 외웁니다. 상품과 서비스에 대한 고객의 질문에 응답하고, 상품의 특징이나 장점을 설명하거나, 각종 행사나 박람회장의 관람객을 안내하는 일을 합니다. 제품에 대한 시범 사용, 시식 및 시음 행사 등을 운영하고 고객이 상품이나 서비스를 직접 체험할 수 있도록 돕고 설명합니다.', '["모델과","이벤트연출과"]', 24430000, '향후 5년간 홍보도우미의 관련 직업인 홍보도우미 및 판촉원의 일자리 규모는 다소 증가할 …', '[]', '영업관련 서비스직', '2026-04-06 07:47:44.934405');
