INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (337, '428', '호스피스전문간호사', '영업·판매·운전·운송직', '호스피스전문간호사는 죽음을 앞둔 말기 환자가 인생을 편안하게 마무리할 수 있도록 돕는 일을 합니다. 죽음이란 삶의 자연스러운 과정이라는 것을 알게 하고, 환자의 정신적, 육체적 고통이 완화될 수 있도록 돕습니다. 환자의 건강 상태와 통증을 확인하고 이를 완화할 수 있도록 간호합니다. 말기 환자와 가족의 심리적 문제나 어려움은 없는지 상태를 평가하고 간호하거나 교육하기도 합니다. 환자의 죽음으로 인해 이별을 겪은 가족들을 위로하고 간호합니다.', '["간호학과"]', 36650000, '향후 5년간 호스피스전문간호사의 관련 직업인 간호사의 일자리 규모는 다소 증가할 전망입니…', '["간호사"]', '보건의료 관련 서비스직', '2026-04-06 07:47:45.992677');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (338, '431', '데이터베이스관리자', '경영·사무·금융·보험직', '데이터베이스관리자는 컴퓨터를 사용하여 각종 데이터를 체계적으로 수집, 정리, 가공하거나 입력하여 데이터베이스를 구축, 관리, 분석하는 일을 합니다. 데이터베이스를 분석하고 전산시스템 사용자에 대한 등록, 데이터 접근 범위, 읽고 쓰기 권한, 사용자 로그인 및 암호를 관리합니다. 데이터베이스 시스템에 장애가 발생하거나 서버 부품의 고장으로 인해 문제가 발생하면 신속히 원인을 파악하고 빠르게 시스템을 복구합니다. 데이터베이스를 매일 또는 정기적으로 백업하거나 보관하여 데이터의 손실을 예방합니다. 고객이 요구하는 특정 분야의 자료를 일정 기간 동안 수집하여 정리하고, 입력된 자료를 검토하여 문제점을 보완합니다.', '["전자공학과","전기전자공학과","정보통신과","정보통신공학과","컴퓨터공학과","컴퓨터응용기계과"]', 46000000, '향후 5년간 데이터베이스관리자의 관련 직업인 데이터베이스개발자의 일자리 규모는 현 상태를…', '["전자계산기기능사","전자계산기기사","전자계산기제어산업기사","전자계산기조직응용기사","정보관리기술사","정보처리기능사","정보처리산업기사","정보처리기사","컴퓨터시스템응용기술사","SQL","데이터아키텍처","리눅스마스터","데이터분석"]', 'IT관련전문직', '2026-04-06 07:47:46.358122');
