INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (341, '440', '시스템엔지니어', '경영·사무·금융·보험직', '시스템엔지니어는 정보 기술의 기술적 사항과 해당 업무에 필요한 사항을 종합적으로 분석하고 설계하여 사용 용도에 따라 가장 빠르면서 안정된 정보시스템을 만드는 일을 합니다. 정보시스템을 도입해 처리할 일을 확인하고 사용자가 일을 처리하는 절차와 관련된 자료를 가지고 정보시스템으로 만들기 위한 모든 요소를 확인합니다. 기존 시스템의 문제점과 고객이 원하는 사항을 자세히 파악하고 분석하여, 만들어야 할 정보시스템의 성능, 기능, 사양 등에 관한 주요 사항을 결정합니다. 만들고자 하는 시스템이 다른 업무를 처리하는 전산 시스템의 데이터와 얼마나 관련되어 있는지를 자세히 검토하여 데이터의 처리에 문제가 없도록 합니다.', '["시스템경영공학과","컴퓨터응용기계과","스마트정보과","시스템공학과","컴퓨터공학과"]', 37300000, '향후 5년간 시스템엔지니어의 관련 직업인 시스템소프트웨어개발자의 일자리 규모는 다소 증가…', '["전자계산기기능사","전자계산기기사","전자계산기제어산업기사","전자계산기조직응용기사","정보관리기술사","정보처리산업기사","정보처리기사","컴퓨터시스템응용기술사","SQL","리눅스마스터","데이터아키텍처"]', 'IT관련전문직', '2026-04-06 07:47:47.542006');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (342, '443', '웹디자이너', '경영·사무·금융·보험직', '웹디자이너는 웹사이트의 첫 화면이나 세부적인 화면, 메뉴의 색상과 아이콘 등 사이트 전체를 디자인하고 만드는 일을 합니다. 웹페이지의 문자, 이미지, 동영상, 음성 등을 재가공하여 이용자들이 알기 쉽고 사용하기 쉽게 만드는 작업을 합니다. 웹사이트의 전체적인 이미지를 결정한 후 사용자가 웹페이지를 이용할 때 메뉴의 이동을 돕는 내비게이션을 디자인하고 전체 구조, 주메뉴와 부메뉴를 위계적으로 정하며, 웹사이트의 틀을 정하고 시각적인 배치를 합니다. 웹사이트의 주요 화면을 필요에 따라 갱신하며 웹사이트를 제작할 때 필요한 기술인 HTML5, CSS, Javascript, JSP, ASP, XML 등을 활용하여 웹에 애니메이션이나 특정한 효과를 구현하기도 합니다.', '["멀티미디어과","산업디자인과","시각디자인과","산업디자인학과","멀티미디어학과","그래픽디자인과","시각디자인학과"]', 35220000, '향후 5년간 웹디자이너의 일자리 규모는 현 상태를 유지할 전망입니다. 웹사이트 모바일 버…', '["웹디자인기능사","컴퓨터그래픽스운용기능사"]', '웹·게임·애니메이션 관련직', '2026-04-06 07:47:47.889422');
