INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (345, '452', '정보중개인', '경영·사무·금융·보험직', '정보중개인은 정보 요구자의 의뢰나 요청에 따라 해당하는 정보의 원천이 어디 있는지를 찾고 이 정보를 고객의 요구 사항에 맞게 가공하여 활용할 수 있는 형태로 제공하는 일을 담당하고 있습니다. 고객의 의뢰 및 요청 사항을 정확히 파악하여 필요한 정보에 대해 정의하고, 인터넷 검색, 문헌 탐색 및 관련 관계자들과의 만남을 통해 정보를 찾아냅니다. 고객의 요구 사항에 가장 적합하도록 습득한 정보를 가공하여 제공합니다.', '["인터넷정보학과","정보통신과","정보통신공학과","경영정보과","경영학과","스마트정보과"]', 43000000, '향후 5년간 정보중개인의 관련 직업인 정보시스템운영자의 일자리 규모는 다소 증가할 전망입…', '["e-TestProfessional","디지털정보활용능력(DIAT)","정보기술자격(ITQ)시험"]', '사무 관련직', '2026-04-06 07:47:48.952452');
