INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (347, '458', '컴퓨터그래픽디자이너', '경영·사무·금융·보험직', '컴퓨터그래픽디자이너는 컴퓨터를 이용해 광고, 영화, 드라마, 애니메이션에 사용되는 특수효과 등 3D 입체 영상이나 도형, 공간, 자막, 그림 등을 디자인하고 표현하는 일을 합니다. 인터넷 홈페이지에 사용되는 여러 가지 새로운 이미지를 생각해내고 제작하며, 웹페이지에 디자인한 이미지를 올립니다. 방송이나 영화 및 게임 시나리오 작가가 생각한 내용 즉, 입체 영상이나 특수효과, 자막, 그림 등을 컴퓨터 그래픽을 사용하여 영상 속에 표현합니다.', '["디지털디자인과","그래픽디자인과","컴퓨터디자인학과"]', 33000000, '향후 5년간 컴퓨터그래픽디자이너의 관련 직업인 영상그래픽디자이너의 일자리 규모는 증가할 …', '["컴퓨터그래픽스운용기능사","GTQ(그래픽기술자격)"]', '디자인 관련직', '2026-04-06 07:47:49.728712');
