INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (350, '467', '의료정보시스템개발자', '영업·판매·운전·운송직', '의료정보시스템개발자는 의료정보의 축적 및 검색, 의료기관 간의 상호 연결 또는 지역주민이 의료기관을 보다 편리하게 이용할 수 있도록 하는 정보시스템을 연구 및 개발하는 일을 합니다. 국내외의 의료정보시스템 개발 흐름 및 우리나라 의료 체계와 관련된 법과 제도를 분석하여 적합한 의료정보시스템을 기획하고 개발합니다. 병원과 환자의 진료 정보 및 기타 의료 행정 정보들을 체계적으로 관리할 수 있는 의료정보시스템을 만듭니다. 의료정보시스템이 작동하는 데 필요한 하드웨어나 네트워크 장비를 정기적으로 점검하고, 시스템의 오류나 결함의 원인을 분석하여 문제를 해결합니다.', '["의료정보시스템과","의료정보공학과","컴퓨터소프트웨어과","소프트웨어공학과","컴퓨터공학과","컴퓨터과","컴퓨터과학과","시스템공학과","정보통신공학과"]', 35610000, '향후 5년간 의료정보시스템개발자의 관련 직업인 의무기록사의 일자리 규모는 다소 증가할 전…', '["전자계산기기능사","전자계산기제어산업기사","전자계산기기사","정보처리기능사","정보처리산업기사","정보처리기사","컴퓨터시스템응용기술사","마이크로소프트 인증 전문가 자격증(MCP)","오라클 자격인증제도","보건의료정보관리사","병원행정사"]', 'IT관련전문직', '2026-04-06 07:47:50.771473');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (351, '470', '전자상거래전문가', '경영·사무·금융·보험직', '전자상거래전문가는 정부, 기업, 개인 등이 인터넷 웹사이트를 통해 상품 및 서비스를 구매할 수 있는 전자상거래 시스템을 설계하고 만드는 일을 합니다. 전자상거래전문가는 사업 기획부터 콘텐츠 개발, 시스템 구성, 서버 관리 및 운영, 상품 구매 및 판매, 마케팅 및 홍보 등을 담당합니다. 인터넷을 통해 물건을 구매할 가능성이 있는 고객과 물건을 판매할 개인과 기업의 요구를 포함한 전자상거래 시스템을 만듭니다. 고객을 대상으로 마케팅 전략을 세우거나 전자상거래의 구축에 대한 전문적인 조언을 합니다. 전자상거래와 관련된 법률적 문제를 검토하고 사이트를 만들고 판매 및 유통 계획을 수립하고 전체 웹사이트의 운영과 관리에 대해 감독합니다.', '["마케팅경영과","정보통신과","정보통신공학과","경영정보과"]', 36260000, '향후 5년간 전자상거래전문가의 관련 직업인 마케팅·광고·홍보사무원의 일자리 규모는 다소 …', '["전자상거래관리사","전자상거래운용사","샵마스터"]', 'IT관련전문직', '2026-04-06 07:47:51.120971');
