INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (353, '476', '무선주파수(RF)엔지니어', '경영·사무·금융·보험직', '무선주파수(RF)엔지니어는 무선주파수(RF: Radio Frequency)를 이용하여 무선통신 장비들을 연구, 개발, 설계하는 일을 합니다. 국내외 시장을 조사하고 경쟁하는 기업의 제품 및 무선통신 장비 관련 기술 변화 등에 대해 분석하여, 새로운 기능과 성능을 갖춘 무선통신 장비를 기획하고 개발합니다. 꾸준한 실험과 검사를 통해 새롭게 개발한 무선통신 장비의 성능과 품질을 검사하고 장비의 결함이나 불량의 원인에 대해 분석하여 해결책을 제시합니다.', '["전자공학과","정보통신공학과","전기전자공학과"]', 43250000, '향후 5년간 무선주파수(RF)엔지니어의 관련 직업인 통신기술개발자의 일자리 규모는 다소 …', '["무선설비산업기사","무선설비기사","RFID기술자격검정"]', '공학 전문직', '2026-04-06 07:47:51.825843');
