INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (374, '539', '소음진동기술자', '연구직 및 공학 기술직', '소음진동기술자는 각종 공사 현장 등에서 기계 및 장비의 사용으로 인해 발생하는 소음과 진동을 측정하고, 생활환경을 오염시키는 소음과 진동을 최소화하거나 해소할 수 있는 방법에 대해 연구 및 개발하는 일을 합니다. 소음과 진동을 측정 및 분석하고 원인을 감소 또는 제거할 수 있는 방지시설이나 방법 등을 연구하고 개발합니다. 소음방지시설의 적합성을 검토하고 시공이나 운전상의 문제점 등을 점검하고 평가하며 이에 대한 해결책을 제시합니다.', '["보건환경과","환경과학과","환경시스템과","환경보건학과","환경공학과"]', 41440000, '향후 5년간 소음진동기술자의 일자리 규모는 다소 증가할 전망입니다. 소음과 진동은 스트레…', '["소음진동산업기사","소음진동기사","소음진동기술사"]', '환경관련 전문직', '2026-04-06 07:47:59.170361');
