INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (403, '626', '여행상품개발원', '설치·정비·생산직', '여행상품개발원은 새로운 여행 상품을 기획 및 개발하고 고객과 상담하는 일을 합니다. 여행지로 활성화되지 않은 지역을 찾아내어 현지답사를 한 다음, 여행에 필요한 상황과 조건을 조사 및 분석하여 새로운 여행지를 개발하고 상품화합니다. 여행과 관련된 모든 상황을 고려하여 여행 계획을 세우며, 이동을 위한 교통수단을 마련하며, 경비, 관광 명소, 숙박 및 편의시설, 편의성 등에 대한 정보를 수집하고, 여행 코스와 일정을 기획하고 총감독합니다. 고객과의 상담을 통해 여행자의 요구를 파악하고, 상품의 특징과 장점을 소개하거나 권유하며 여행 계획에 대해 전문적인 조언을 합니다. 해외여행의 경우 항공권 예약, 여권 발급, 비자 신청 및 발급, 외환 환전 등 여행에 필요한 업무를 대신하기도 합니다.', '["관광통역과","문화관광과","호텔경영과","관광경영학과"]', 35160000, '향후 5년간 여행상품개발원의 관련 직업인 여행상품개발자의 일자리 규모는 현 상태를 유지할…', '["국내여행안내사","관광통역안내사"]', '기획서비스직', '2026-04-06 07:48:09.452182');
