INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (441, '740', '귀금속 및 보석세공원', '보건·의료직', '귀금속 및 보석세공원은 귀금속으로 장신구를 디자인하고 제작하는 일을 하거나 보석에 모양을 만들고 광택을 내는 일을 합니다. 원석의 가치와 순도, 물리적 구조, 색 등급 및 기타 관련 요소를 판단하기 위해 특성을 검사하는 일도 합니다. 디자인된 도면을 보고, 금, 은, 백금 등의 귀금속을 소재로 실톱대, 줄, 벼랑공구, 압연기 등 수공구 및 기계 기구를 사용하여 정확한 치수와 함량으로 금속 원형을 제작합니다. 귀금속 재료를 형틀에 부어 주조하거나 조각 및 용접하여 특정한 형태로 가공합니다. 제작한 귀금속에 보석을 알맞은 크기로 가공하여 맞춰 끼우거나 확대경을 사용해 불순물, 깨짐, 표면 상태, 규격 등을 검사하거나 결함을 수리합니다.', '["금속공예과","공예학과","산업디자인과","공예과","시각디자인학과","산업디자인학과","금속공예학과","시각디자인과"]', 36260000, '향후 5년간 귀금속 및 보석세공원의 일자리 규모는 다소 감소할 전망입니다. 최근 3D프린…', '["귀금속가공기능사","귀금속가공산업기사","귀금속가공기능장","보석가공기능사"]', '기타 특수 예술직', '2026-04-06 07:48:22.908816');
