INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (498, '911', '조명기사', '예술·디자인·방송·스포츠직', '조명기사는 연극, 영화, 무용, 뮤지컬, 콘서트, 방송 드라마 등의 제작을 위해 조명 장치를 설치하고 조종하는 일을 합니다. 무대에 올릴 작품의 내용, 제작 의도, 성격 등을 정확하게 파악한 다음 대본이나 기본 설계도를 보고 조명 감독과 협의하여 조명 계획을 세웁니다. 무대 공연에서 출연자의 움직임에 따라 집중 조명 설비를 조작하거나 조명의 밝기, 조명 사용 시간, 조명 색상 등을 조정합니다. 영화나 방송 촬영 현장의 상황에 따라 축전지 또는 발전기의 사용 여부를 결정하고 투광조명기, 반사판, 집중조명 등을 배치하고 조명 장비를 설치합니다. 작품의 공연이나 촬영에 필요한 전반적인 조명 상태를 파악하고 조명의 움직임을 결정합니다.', '["전자공학과","전기과","방송제작과","전기공학과","연극영화과","연극영화학과","방송영상과","전자과","전기전자공학과"]', 40200000, '향후 5년간 조명기사의 관련 직업인 조명·영사기사의 일자리 규모는 현 상태를 유지할 전망…', '["무대예술전문인","방송통신기능사","방송통신산업기사","방송통신기사"]', '영상 관련직', '2026-04-06 07:48:43.107101');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (499, '914', '영화시나리오작가', '경영·사무·금융·보험직', '영화시나리오작가는 영화 제작을 위해 작품의 주제를 선정하고, 새로운 영화 대본을 창작하거나 기존의 작품(문학, 웹툰, 드라마 등)을 각색하여 대본을 집필합니다. 영화의 주제를 선택하고 내용에 따른 역사적 사실이나 사건의 과정 등을 세밀하게 조사 및 분석하여 작품의 전체 줄거리를 구상합니다. 영화 및 애니메이션 제작을 위해 작품의 주제를 선택하고 주인공이나 등장인물의 성격, 시대적 배경과 장소 등을 결정합니다. 작품의 내용에 따른 등장인물, 시대, 장소 등을 결정하고 영화의 진행에 필요한 대사 내용이나 동작 등을 구상합니다.', '["문예창작학과","문예창작과","신문방송학과","국어국문학과"]', 25000000, '향후 5년간 영화시나리오작가의 일자리 규모는 현 상태를 유지하는 수준이 될 전망입니다. …', '[]', '작가 관련직', '2026-04-06 07:48:43.462874');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (500, '917', '음반기획자', '경영·사무·금융·보험직', '음반기획자는 국외 음반 시장의 상황과 음반 구매자의 요구를 분석하고 제작할 음반의 주제와 내용을 기획하는 일을 합니다. 음반 구매자가 요구하는 음악의 주제나 스타일을 찾기 위해 다양한 마케팅 조사를 실시합니다. 음악감독과의 회의를 통해 음반의 주제를 선정하고, 음반의 주제에 맞는 가수, 연주자, 작곡가, 작사가, 편곡가 등을 정하고 작사, 작곡 및 편곡, 녹음 등의 과정을 거쳐 음반으로 제작합니다. 음반이 완성되면 방송 출연 및 신문사, 잡지사와 같은 홍보 매체와의 인터뷰 등을 계획하거나 SNS를 활용하는 등 음반의 홍보와 판매 전략을 기획합니다. 각종 가요제, 방송 드라마 등의 방송 출연이 확정되면 방송연출가와 회의하여 음악 홍보를 위한 전반적인 사항을 기획 및 총괄합니다.', '["음악과","실용음악과","음악학과","실용음악학과"]', 45790000, '향후 5년간 음반기획자의 관련 직업인 공연기획자의 일자리 규모는 다소 증가할 전망입니다.…', '[]', '음악 관련직', '2026-04-06 07:48:43.817255');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (501, '920', '애니메이션기획자', '연구직 및 공학 기술직', '애니메이션기획자는 애니메이션의 제작에 필요한 각종 업무를 기획하고 조정하는 일을 합니다. 역사나 문화에 관련된 다양한 자료를 읽고 조사하여 애니메이션 작품의 새로운 소재를 발굴하거나 애니메이션의 주제 및 내용의 전체 방향을 결정합니다. 애니메이션 제작에 필요한 예상 인력, 비용, 필요한 제작 기간 등에 대한 전체 예산을 기획하고, 기타 제작에 필요한 사항들을 조정하며 제작 인력 등을 섭외하고 제작을 총감독합니다. 각 장면에 따라 캐릭터를 연기하는 성우에게 분위기, 동작 등을 설명하고 지도합니다. 애니메이션의 제작이 결정되면, 애니메이션의 홍보와 마케팅, 배급 등에 대한 사항을 기획하고 실행합니다.', '["만화애니메이션학과","애니메이션과"]', 45790000, '향후 5년간 애니메이션기획자의 관련 직업인 공연기획자의 일자리 규모는 다소 증가할 전망입…', '[]', '예술기획 관련직', '2026-04-06 07:48:44.168547');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (502, '923', '게임기획자', '설치·정비·생산직', '게임기획자는 PC 게임, 모바일 게임, 콘솔 게임 등 게임용 소프트웨어 제작과 관련된 모든 사항을 기획하고 감독합니다. 국외의 게임 시장 조사를 통해 소비자들이 원하는 게임이 무엇인지를 확인하고, 새로운 게임 제작을 위한 아이디어를 내거나 이에 대한 기획안을 작성합니다. 게임의 장르와 이용 연령층, 게임의 난이도, 게임 내 각종 캐릭터 역할과 특징, 기본적인 스토리 흐름을 설정하고, 그래픽 디자이너, 컴퓨터 프로그래머 등과 함께 게임 소프트웨어를 제작합니다. 게임 소프트웨어에 대한 공개 전 테스트를 하고 시연회에 참여하는 등 홍보와 마케팅 업무를 기획합니다. 게임의 제작이 완료되면, 게임을 운영하면서 이용자들이 요구하는 개선 사항이나 의견을 듣고 게임 소프트웨어를 수정하거나 더 나은 기능으로 최신화시킵니다.', '["정보통신공학과","응용소프트웨어공학과","컴퓨터공학과","전자공학과"]', 45790000, '향후 5년간 게임기획자의 관련 직업인 공연기획자의 일자리 규모는 다소 증가할 전망입니다.…', '["게임기획전문가"]', '예술기획 관련직', '2026-04-06 07:48:44.522258');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (503, '926', '출판편집자', '연구직 및 공학 기술직', '출판편집자는 작가가 쓴 원고의 내용을 검토하고 작성 내용의 손상 없이 원고의 오타나 맞춤법 등을 수정하는 교정, 문법에 맞지 않는 문장을 고치는 교열, 글을 다듬는 윤문 작업을 합니다. 원고를 받아서 출판물의 디자인을 검토하고, 편집 작업의 순서와 방법을 결정합니다. 작가와 출판 기획자와의 상의를 통해 책의 내용에 맞는 글씨체, 디자인, 책의 크기와 규격인 판형 등을 결정하고 알맞은 양식에 따라 원고의 내용을 편집합니다. 디자인 설계부터 편집까지의 모든 작업을 수행하기도 하며, 디자인 프로그램인 일러스트, 포토샵 등을 이용하여 사진을 합성 또는 수정하여 더욱 좋은 이미지를 만듭니다. 출판 편집 전문 프로그램을 이용하여 문자나 그림, 로고, 사진 등을 입력하고 색채, 크기, 위치를 조정, 편집하고 시험 출력을 통해 문제점을 보완하고 인쇄하기 전 인쇄판에 사용될 최종 자료를 만듭니다.', '["국어국문학과","미디어출판과"]', 34000000, '향후 5년간 출판편집자의 관련 직업인 출판물편집자의 일자리 규모는 감소할 전망입니다. 출…', '[]', '언어 관련 전문직', '2026-04-06 07:48:44.879271');
