INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (504, '929', '공예원', '연구직 및 공학 기술직', '공예원은 목재, 석재, 점토, 금속, 종이 등 다양한 소재를 가지고 손이나 도구를 이용하여 각종 수공예품이나 전통공예품을 만듭니다. 공예원은 사용하는 재료나 만드는 제품에 따라 목공예원, 석공예원, 도자기공예원, 금속공예원 등으로 구분되며, 목공예원은 나무를 이용하여 목기 제품, 실내 장식장, 일반 가구 등을 제작합니다. 석공예원은 석불, 석탑, 석등, 비석 등의 석물제품을 만듭니다. 도자기공예원은 각종 식기류, 타일, 액자 등을 만듭니다. 금속공예원은 금, 은, 동 ,철과 같은 금속재료를 가지고 각종 장신구, 장식품, 촛대 등의 생활용품을 제작합니다.', '["공예학과","산업디자인과","도자기공예과","금속공예학과","공예과","산업디자인학과","금속공예과","공예디자인학과"]', 33080000, '향후 5년간 공예원의 일자리 규모는 현 상태를 유지할 전망입니다. 정부에서는 공예산업을 …', '[]', '미술 및 공예 관련직', '2026-04-06 07:48:45.23465');
