INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (507, '938', '정보시스템운영자', '교육·법률·사회복지·경찰·소방직 및 군인', '정보시스템운영자는 기업이나 기관에서 운영하고 있는 정보시스템을 안전하고 체계적으로 운영 및 관리하고 사용자들에게 서비스를 제공하는 일을 합니다. 정보시스템의 하드웨어나 네트워크 장비는 외부 환경에 영향을 받기 쉬우므로 전산실 내부의 온도, 습도, 먼지 등을 체크하고 쾌적하게 유지될 수 있도록 합니다. 정보시스템의 사용자에 대한 등록 및 삭제에 대한 관리와 각 기능별 사용 권한을 주거나, 시스템 내의 정보를 외부로부터 보호하기 위해 기술적 장치를 마련하고 정기적으로 데이터를 원래 상태로 복구할 수 있는 형태로 보관합니다. 시스템을 운영하면서 문제점이나 오류 및 고장이 발생하면, 즉시 원인을 파악하여 시스템을 빠른 시간 내에 복구합니다.', '["시스템공학과","시스템경영공학과","컴퓨터공학과","정보통신공학과"]', 43000000, '향후 5년간 정보시스템운영자의 일자리 규모는 다소 증가할 전망입니다. 서버, 네트워크 등…', '["전자계산기조직응용기사","정보관리기술사","정보처리기능사","정보처리기사","정보처리산업기사","마이크로소프트 인증 전문가 자격증(MCP)","오라클 자격인증제도","SQL"]', 'IT관련전문직', '2026-04-06 07:48:46.291074');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (508, '941', '임상병리사', '연구직 및 공학 기술직', '임상병리사는 질병의 예방과 진단, 치료를 돕기 위해 환자의 혈액, 소변, 체액, 생체 조직 등을 이용하여 각종 의학적 검사를 수행하고 분석합니다. 응고, 착색 등의 기법을 적용하여 인체의 기관, 조직, 세포, 혈액, 분비물 등의 검사물을 준비하고 검사, 분석, 실험을 합니다. 진단 혈액 검사, 미생물 검사, 수혈 의학 검사, 진단 분자 유전 검사, 면역 혈청 검사 등을 통해서 질병의 원인을 찾아냅니다. 인체의 기관, 조직, 세포, 혈액, 분비물 등의 여러 가지 검사물에 대해 현미경 등의 기구나 시약을 사용하여 검사, 분석하여 질병의 여부를 확인하고, 혈액형 및 혈구 수 계산 등의 검사 결과를 확인합니다. 검사용 시약을 만들거나 채혈을 하고 혈액을 보존하여 검사와 실험 과정을 정확하게 기록하여 의사에게 제공합니다.', '["임상병리학과","임상병리과"]', 32000000, '향후 5년간 임상병리사의 일자리 규모는 다소 증가할 전망입니다. 단순한 검사는 수탁 검사…', '["임상병리사"]', '의료관련 전문직', '2026-04-06 07:48:46.645653');
