INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (526, '995', '에너지공학기술자', '경영·사무·금융·보험직', '에너지공학기술자는 에너지 사업을 위한 기술상의 조건을 분석하며 이에 필요한 시스템 장비를 설계, 계획, 조직화합니다. 광산 개발 관련 업무를 수행하고, 광산 시설, 시스템 및 장비를 설계하며 지하의 금속 또는 비금속광물, 광석의 추출을 계획 및 조직합니다. 석유 및 가스 매장량의 탐사, 개발, 추출과 관련된 연구를 수행하며, 광석 매장량 및 보유량 추정 및 탄광 설계에 관한 측량 및 연구를 수행합니다.', '["에너지자원공학과","원자력공학과"]', 50000000, '향후 5년간 에너지공학기술자의 일자리 규모는 다소 증가할 전망입니다. 최근 우리 사회는 …', '["방사선관리기술사","방사선취급감독자","에너지관리기사","에너지관리산업기사","원자력기사","원자력발전기술사","핵연료물질취급감독자","핵연료물질취급자"]', '공학 전문직', '2026-04-06 07:48:53.033811');
