INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (529, '1004', '환경설비기술자', '교육·법률·사회복지·경찰·소방직 및 군인', '환경설비기술자는 폐수ㆍ폐기물 처리 설비기기 및 장치를 조작하는 등의 일을 담당합니다. 연구자의 관리하에 오염물질의 유입량 및 유입 오염물질의 변화를 살피고 이와 관련한 실험을 관찰하고 결과를 기록합니다. 폐수처리 및 폐기물 처리 기기 및 장치를 조작하고, 장치의 가동, 보수, 개조 등의 업무 사항을 작업 일지에 기록합니다.', '["환경공학과","보건환경과","환경과학과","환경시스템과"]', 38330000, '향후 5년 동안 환경설비기술자의 관련 직업인 폐기물처리기술자의 일자리 규모는 증가할 전망…', '["수질환경기사","수질환경산업기사","토양환경기술사","폐기물처리기사","폐기물처리기술사","폐기물처리산업기사"]', '공학 기술직', '2026-04-06 07:48:54.067367');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (530, '1007', '상수도기술자', '예술·디자인·방송·스포츠직', '상수도기술자는 안전한 수돗물을 생산해 사람들에게 공급하기 위해 상수도의 수질 상태를 지속적으로 검사하고, 정수 처리 대응 방안 및 배급수의 효과적인 유지, 관리 방법 등에 대해 연구하고 개발합니다. 상수원을 지속적으로 관리하고 검사하여 향후 수질 변화를 예측합니다. 수리학적 현상 및 수질 변화 예측, 물 수요 예측 등의 방법을 적용하여 배급수의 효과적인 유지 및 관리 방법에 대해 연구하고 개발합니다.', '["환경공학과","토목공학과","환경보건학과","환경과학과"]', 37150000, '향후 5년간 상수도기술자의 고용은 증가할 전망입니다. 전 세계적으로 폐기물이 증가하고, …', '["상하수도기술사","수질관리기술사","수질환경기사","수질환경산업기사"]', '공학 전문직', '2026-04-06 07:48:54.4151');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (531, '1010', '방사성폐기물관리원', '연구직 및 공학 기술직', '방사성폐기물관리원은 원자력시설 혹은 방사성물질을 다루는 작업장과 실험실에서 나오는 폐기물 처리 설비 및 용기를 관리하고, 작업원을 감독합니다. 방사성폐기물 처리 장치를 조작하고, 방사성폐기물의 처리가 제대로 되었는지를 확인합니다. 작업장의 방사능오염을 방지하기 위해 방사성물질 취급자를 감독하거나 방사성동위원소 등의 사용, 저장, 운반 등에 관련된 사항들을 수행합니다.', '["원자력공학과"]', 38330000, '향후 5년간 방사성폐기물관리원의 고용은 증가할 것으로 전망됩니다. 자원에너지 위기와 환경…', '["원자력기사","원자력발전기술사","핵연료물질취급자"]', '공학 기술직', '2026-04-06 07:48:54.773411');
