INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (548, '1061', '국회의원', '교육·법률·사회복지·경찰·소방직 및 군인', '국회의원은 선거를 통해 선출된 국민의 대표로서 국회에서 헌법과 법률의 개정 및 의결과 관련된 일을 하고, 정부 예산안을 심의 및 확정하는 등의 업무를 담당합니다. 헌법과 법률에 규정된 개정 절차에 따라 특정 조항을 수정 및 삭제하거나 새로운 조항을 추가합니다. 정부의 예산안에 대한 심의와 수정을 통해 예산안을 확정합니다.', '["법학과","국제학부","사회학과","정치외교학과","경제학과","경영학과","행정학과"]', 93240000, '향후 5년간 국회의원의 고용은 현 상태를 유지할 전망입니다. 국회의원의 정족수는 법률상으…', '[]', '법률 및 사회활동 관련직', '2026-04-06 07:49:00.785517');
