INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (557, '1088', '스포츠에이전트', '경영·사무·금융·보험직', '스포츠에이전트는 스포츠 관련 프로그램 및 서비스를 개발하고 운영을 위한 기획 및 절차를 조직하여 조정 및 관리합니다. 시합이나 경기에 관한 정보를 수집하고 훈련 과정을 설계하기도 하며 스포츠 관련 회사와 소속 선수를 연결하여 계약을 성사시킵니다. 선수를 돌보고 스케줄 관리를 하는 것은 물론 선수의 이미지 관리, 운동량 관리, 광고 계약 체결, 연봉 협상, 언론 홍보, 팬클럽 관리 등을 합니다.', '["체육학과","사회체육학과","스포츠건강관리학과","법학과","경제학과","경영학과"]', 42480000, '향후 5년간 스포츠에이전트의 고용은 다소 증가할 전망입니다. 건강과 여가에 대한 관심이 …', '[]', '매니지먼트 관련직', '2026-04-06 07:49:04.00784');
