INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (560, '1097', '프로게이머', '영업·판매·운전·운송직', '프로게이머는 각종 컴퓨터게임 대회에 참가하여 게임을 합니다. 프로게이머는 게임감독, 팀원들과 함께 전략시뮬레이션, 롤플레잉, 액션게임, 온라인게임 등 컴퓨터게임에 대한 기술 및 전략을 익히고 꾸준히 연습하여 각종 대회에 참가합니다. 소속 회사에서 개발한 새로운 게임소프트웨어에 대한 테스트를 하며, 새 게임소프트웨어가 출시되면 시연회와 홍보를 하기도 합니다.', '["게임공학과","게임콘텐츠과"]', 51800000, '향후 5년간 프로게이머의 고용은 다소 증가할 것으로 보입니다. 초고속 인터넷의 확산과 인…', '[]', '기타 게임·오락·스포츠 관련직', '2026-04-06 07:49:05.087051');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (561, '1100', '군무원', '연구직 및 공학 기술직', '군무원은 군부대에서 군인과 함께 근무하는 특정직 국가 공무원으로서 담당 직렬에 따라 기술, 연구, 일반 행정, 이미용 등에 대한 업무를 수행합니다. 국민에 대한 봉사자로서 직업윤리 정신을 바탕으로 공공의 이익을 실현하고 공무를 올바르게 수행합니다. 업무 분야에 대한 전문 지식을 활용하여 보고서 및 문서를 작성하고 관리합니다.', '[]', 36000000, '향후 5년간 군무원의 고용은 현 상태를 유지할 전망입니다. 저출산에 따른 병력 자원의 양…', '[]', '사무 관련직', '2026-04-06 07:49:05.438142');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (562, '1103', '교육학연구원', '연구직 및 공학 기술직', '교육학연구원은 교육의 목적, 내용, 방법 등에 관한 종합적이며 과학적인 연구를 실시하고, 합리적인 교육체제 및 방법을 설계하고 개발합니다. 교육체제 및 방법 등 교육 전반에 관련된 문제를 분석하고 평가합니다. 우리나라 교육체계가 당면하고 있는 제반 문제들을 합리적으로 해결할 수 있는 혁신적이고 선진화된 교육체제 및 방법에 대해 연구하고 개발합니다.', '["교육학과","교육공학과"]', 51800000, '향후 5년간 교육학연구원의 고용은 현 상태를 유지할 전망입니다. 교육학연구원을 비롯한 인…', '[]', '인문 및 사회과학 관련직', '2026-04-06 07:49:05.795513');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (563, '1106', '학습지방문교사', '설치·정비·생산직', '학습지를 받아보는 회원의 가정을 직접 방문하여 일정 시간 동안 회원의 학습을 도와줍니다. 업무 지역이 배정되면 회원 및 회원 보호자와 가정방문 시간을 협의하고, 회원별 학습 진도를 계획합니다. 보통 1주일에 한 번 정도 회원의 가정에 방문하여 학습지를 전달하고, 학습지를 활용하여 한 과목당 약 10여 분간 수업을 진행합니다.', '[]', 30560000, NULL, '[]', '교육관련 서비스직', '2026-04-06 07:49:06.146143');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (564, '1109', '서예가', '예술·디자인·방송·스포츠직', '서예가는 먹과 붓을 이용하여 화선지에 글이나 시를 쓰거나 사군자를 그리는 일을 합니다. 완성된 작품에 대하여 표구(그림의 뒷면이나 테두리에 종이 또는 천을 발라서 꾸미는 일)를 의뢰합니다. 개인 작품 전시회를 개최하여 사람들에게 본인의 작품을 소개합니다.', '["미술학과","회화학과","동양화과"]', 31540000, '향후 5년간 서예가의 일자리 규모는 다소 감소할 것으로 전망됩니다. 여가 활동과 정신 건…', '[]', '미술 및 공예 관련직', '2026-04-06 07:49:06.497348');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (565, '1112', '선박갑판원', '교육·법률·사회복지·경찰·소방직 및 군인', '선박갑판원은 각종 선박의 갑판 시설 및 장비를 조작, 유지, 보수하는 데 관련된 제반 업무 및 선박의 운행 관련 업무를 담당합니다. 선박의 구명 장비, 화물 취급 설비, 닻, 케이블 등의 장비를 점검 및 수리하고, 갑판에 설치된 시설물 및 장비를 보수하며, 선체의 부식과 마멸을 방지하기 위하여 선박에 페인트를 도장하거나 선체를 정비합니다. 갑판에 설치된 시설물 및 장비를 일정한 운전 시간마다 점검하고 소모된 부품을 교체합니다.', '[]', 36260000, '향후 5년간 선박갑판원의 일자리 규모는 감소할 전망입니다. 해양수산부의 자료에 따르면 선…', '["운항사"]', '일반운전 관련직', '2026-04-06 07:49:06.854342');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (566, '1115', '주유원', '건설·채굴직', '주유원은 주유소나 가스충전소에 고용되어 자동차의 연료를 주입하고 판매하며, 그 외에도 엔진오일 등의 기타 자동차 소모품을 판매하거나 자동차의 세차를 담당합니다. 주유소나 가스충전소에 자동차가 들어오면, 자동차를 원하는 주유 위치로 안내합니다. 고객이 원하는 주유량을 확인한 다음, 자동차의 연료 주입구를 열고 주유기를 조작하여 연료를 주입하고 주유량에 따른 요금을 계산합니다.', '[]', 25950000, '향후 5년간 주유원의 일자리 규모는 감소할 전망입니다. 고유가 때문에 가격 경쟁력을 높이…', '[]', '영업관련 서비스직', '2026-04-06 07:49:07.20953');
