INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (567, '1118', '무인경비시스템종사원', '연구직 및 공학 기술직', '무인경비시스템종사원은 가정이나 사업체에 설치되어 있는 보안 기기에 이상이 감지되면 현장에 출동하여 이상 원인을 확인 및 처리하여 상황을 정리하는 일을 담당합니다. 침입, 화재, 가스 누출, 보안 기기의 사용 미숙 및 자체 고장 등의 원인으로 인해 보안 기기가 감지한 이상에 대해서 사업서비스업체의 대처 지시를 받고 출동합니다. 이상 내용을 판단하여 정상화하고 사고 확대 방지, 재발 방지, 원상 복구 등의 조치를 하여 보고합니다.', '["경호스포츠과","경찰행정학과","경찰행정과","경호학과"]', 24860000, '향후 5년간 무인경비시스템종사원의 일자리 규모는 다소 증가할 전망입니다. 국민 생활수준이…', '["934"]', '안전 관련직', '2026-04-06 07:49:07.579019');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (568, '1121', '이용사', '연구직 및 공학 기술직', '이용사는 주로 남성 고객을 대상으로 머리카락, 수염을 자르고 손질하는 등의 이용 서비스를 제공합니다. 고객의 얼굴과 머리 형태에 맞는 헤어스타일을 권하고, 고객의 요구에 따라 헤어스타일을 결정합니다. 가위, 이발용 커트기, 빗 등의 이용 기구를 사용하여 고객의 머리카락을 자르고 원하는 형태로 만듭니다. 면도칼과 비누 거품을 사용하여 고객의 수염을 면도해 줍니다.', '["미용과","뷰티미용학과","피부미용과"]', 26420000, '향후 5년간 이용사의 고용은 다소 감소할 것으로 전망됩니다. 소득수준과 생활수준의 향상으…', '["이용장","이용사"]', '이미용 관련직', '2026-04-06 07:49:07.93075');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (569, '1124', '혼례종사원', '연구직 및 공학 기술직', '혼례종사원은 결혼식의 원활한 진행을 위해 의자, 카펫 등을 정리하고 필요한 자료와 물품을 준비하는 등의 일을 담당합니다. 예식 진행 과정을 관찰하여 신랑, 신부의 의상과 행동을 교정해주고, 결혼식순을 도와줍니다. 결혼식 행진 연주자, 전문 주례사를 주선하며, 때에 따라서 직접 연주를 하거나 주례를 담당하기도 합니다. 결혼식장 사용에 대한 고객의 질문에 응하고, 결혼식장 사용 비용을 계산합니다.', '[]', 22790000, '향후 5년간 혼례종사원의 고용은 다소 감소할 것입니다. 점점 결혼식이 줄어들면서 이들의 …', '[]', '매니지먼트 관련직', '2026-04-06 07:49:08.285645');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (570, '1127', '접객원', '예술·디자인·방송·스포츠직', '접객원은 레스토랑이나 호텔 등에서 고객에게 음식이나 음료의 주문을 받고, 각종 서비스를 제공하는 일을 담당합니다. 용모와 복장을 단정히 하여 고객을 맞을 준비를 하며, 청소를 하거나 집기를 준비하고 테이블 정돈을 합니다. 고객에게 자리를 안내하며 메뉴판을 제시하고, 고객의 질문에 답하거나 음식과 음료를 추천합니다. 주문된 음식이 나오면 고객에게 제공하고, 식사가 끝난 고객의 빈 그릇들을 정리합니다. 고객이 계산서를 요구할 경우에는 작성된 계산서를 제시합니다.', '["관광경영과","호텔경영과","호텔외식경영과"]', 24930000, '향후 5년간 접객원의 관련 직업인 홀서빙원의 고용은 다소 감소할 것으로 전망됩니다. 음식…', '[]', '영업관련 서비스직', '2026-04-06 07:49:08.636788');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (571, '1130', '건설견적원', '경영·사무·금융·보험직', '건설견적원은 도로, 교량, 건축구조물, 전기 및 기계 설비 등의 공사 비용을 분석하고 이에 대한 견적서를 작성하는 일을 담당합니다. 시장가격, 설계 도면, 각종 내역서에 기초하여 건설사업에 필요한 자재, 노동력, 장비 등에 대한 비용 견적서를 작성합니다. 입찰 방법, 경쟁업체 등을 파악하고, 관련 자료 분석을 통해 낙찰 가능한 입찰 금액을 계산합니다. 공사 규모에 따라 필요한 인력의 비용을 고려하여 전체적인 공사비를 산출하고, 입찰과 관련된 서류를 작성합니다.', '["건축공학과","건축과","건축학과","토목공학과","토목과"]', 42780000, '향후 5년간 건설견적원의 관련 직업인 건축시공기술자 및 견적원의 고용은 현 상태를 유지하…', '[]', '공학 기술직', '2026-04-06 07:49:09.010008');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (572, '1133', '유리부착원', '경영·사무·금융·보험직', '유리부착원은 건축물의 창문, 문, 진열장, 기타 틀에 부착할 각종 유리를 절단하고 부착합니다. 건물 도면을 보거나 유리를 부착할 건축물을 직접 검토하고 의뢰인과의 협의를 통해 유리의 종류와 디자인을 결정합니다. 다양한 수공구와 작업보조구를 사용하여 유리를 절단하고 연마하여 틀에 유리를 끼우고 마감재로 이음매 부분을 막아 유리를 고정시킵니다. 유리 부착 작업이 완료된 후에는 잘못된 부분이 없는지 확인하고 수정합니다.', '["건축공학과","토목과","건축과","도시건설과"]', 36260000, '앞으로 유리부착원의 고용은 현 상태를 유지할 것으로 전망됩니다. 높은 주택보급률, 저출산…', '["유리시공기능사"]', '기능직', '2026-04-06 07:49:09.360314');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (573, '1136', '항공기·선박조립 및 검사원', '교육·법률·사회복지·경찰·소방직 및 군인', '항공기ㆍ선박 조립 및 검사원은 항공기 또는 선박을 만들기 위해 외장 부분과 내부 부속품을 조립하는 일을 합니다. 부품, 하위 부품과 최종 완성품을 검사하고, 수행한 작업이 품질기준에 적합한지를 확인합니다. 엔진 등의 구성품을 용접기, 동력 공구, 기중기 등을 사용하여 항공기 또는 선박에 탑재합니다. 손, 공구, 설비를 사용하며, 로봇이나 자동 조립 설비를 사용하기도 합니다.', '["항공정비과"]', 39180000, '향후 항공기·선박 조립 및 검사원의 관련 직업인 선박조립원의 일자리 규모는 현 상태를 유…', '["기계가공조립기능사","기계조립산업기사"]', '기능직', '2026-04-06 07:49:09.712229');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (574, '1139', '단조원', '연구직 및 공학 기술직', '단조원은 해머나 단조프레스 등의 기계를 이용하여 쇠붙이와 같은 금속재료에 열을 가하고, 두들기거나 압력을 가하여 원하는 형태의 제품으로 가공하는 일을 담당합니다. 도면과 작업 지시서를 검토하여 작업에 필요한 해머, 단조프레스 등의 도구와 금속재료를 준비합니다. 가열한 금속재료를 해머나 단조프레스 등을 사용하여 금속의 품질을 개선하고 유연한 형태로 가공합니다. 도면과 완성된 제품을 비교하여 제품의 결함 여부와 길이나 크기가 정확한지에 대해 확인합니다.', '["금속공학과","제철금속과"]', 35000000, '향후 단조원 및 단조기조작원의 일자리 규모는 감소할 것으로 전망됩니다. 최근 들어 단조 …', '["금속재료기능장","금속재료기술사","금속재료산업기사","금속재료기사"]', '기능직', '2026-04-06 07:49:10.06792');
