INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (575, '1142', '의복수선원', '연구직 및 공학 기술직', '의복수선원은 고객의 요청에 따라 옷, 모자, 장갑 등 의류제품의 불량 상태를 개선하거나 의류제품의 치수나 길이를 조정하는 일을 담당합니다. 고객과의 상담 또는 작업지시서에 따라 의류제품의 수선 부위나 수선 방향을 확인합니다. 수선에 필요한 천이나 실 등의 재료를 준비합니다. 재봉틀을 조작하거나 바느질을 하여 의류제품을 수선합니다. 금속제품의 부식을 방지하기 위해 화학물 처리 및 가열 장비를 조작합니다.', '[]', 25900000, '향후 의복수선원의 관련 직업인 의복·가죽 및 모피수선원의 일자리 규모는 다소 감소할 전망…', '["양복기능사","양장기능사"]', '의복제조 관련직', '2026-04-06 07:49:10.42073');
