INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (577, '1148', '통신설비설치 및 수리원', '교육·법률·사회복지·경찰·소방직 및 군인', '통신설비설치 및 수리원은 유선전화, 휴대폰, 무선통신기, 무선전화 등의 각종 유선이나 무선통신장비를 설치하고 수리하는 일을 담당합니다. 유선전화, 휴대폰, 무선전화, 무선통신기 등의 송신과 수신을 이어주기 위한 설계도에 따라 통신장비 설치 위치를 확인하고, 통신장비를 설비합니다. 설비한 통신장비가 잘 작동하는지 확인하며, 이상이나 고장이 발생하면 이를 수리합니다.', '["전기전자과","정보통신과","전자과"]', 35000000, '향후 통신설비설치 및 수리원의 관련 직업인 통신·방송 및 인터넷케이블설치 및 수리원의 일…', '["정보통신기사","정보통신기술사","정보통신산업기사"]', '기능직', '2026-04-06 07:49:11.129076');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (578, '1151', '종이제품생산직(기계조작)', '보건·의료직', '종이제품생산직(기계조작)은 종이 가방, 상자, 종이컵 등의 종이 제품을 생산하기 위해 각종 기계를 조작하는 일을 담당합니다. 필요한 길이로 종이를 자르거나 상자를 만들기 위해 판지를 자르고 접는 기계를 조작합니다. 종이를 접고 풀칠을 해서 봉투, 포대를 제조하거나 셀로판지 또는 유사 재료로 봉투를 만드는 기계를 조작합니다. 정기적으로 관련 기계를 점검하고 정비합니다.', '[]', 33580000, '향후 종이제품생산직(기계조작)의 관련 직업인 종이제품생산기조작원의 일자리 규모는 현 상태…', '[]', '기능직', '2026-04-06 07:49:11.485876');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (579, '1154', '채소 및 특용작물재배자', '보건·의료직', '채소 및 특용작물재배자는 상추, 배추, 쑥갓 등 채소 작물과 인삼 등의 특용작물을 재배하고 수확하는 일을 합니다. 재배할 작물의 종류와 양, 재배면적을 결정하고 계획을 세웁니다. 농기계류, 기구, 재배할 작물, 경작지를 준비하고 작물의 종류에 따라 재배 방법을 결정합니다. 작지에 종자를 심고 필요에 따라 비료와 농약을 사용하여 채소 및 특용작물을 재배합니다. 다 자란 채소나 특용작물들은 수확하여 시장에 판매하기 위한 준비를 합니다.', '["농수산과","식물자원학과"]', 33000000, '향후 채소 및 특용작물재배자의 관련 직업인 채소작물재배원의 일자리 규모는 감소할 것으로 …', '["농기계운전기능사","농기계정비기능사","농업기계기사","농업기계산업기사"]', '농생명산업 관련직', '2026-04-06 07:49:11.839559');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (580, '1157', '원양어부', '예술·디자인·방송·스포츠직', '원양어부는 먼바다로 나아가 참치, 대구 등의 물고기를 잡습니다. 그물 등의 장비나 미끼를 이용하여 물고기를 잡고, 잡은 고기들을 종류별로 분류합니다. 잡은 물고기 등은 씻어서 소금에 절이거나 냉동고에 보관하여 시장에 판매할 준비를 합니다.', '[]', 24430000, '향후 원양어부의 관련 직업인 어부 및 해녀의 일자리 규모는 감소할 것으로 전망됩니다. 어…', '["어업기술사","어로산업기사","어업생산관리기사","잠수기능사","잠수산업기사"]', '농생명산업 관련직', '2026-04-06 07:49:12.187557');
