INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (613, '1256', '커플매니저', '연구직 및 공학 기술직', '커플매니저는 결혼을 전제로 이성과의 교제를 계획하는 남녀 고객들에게 각자의 이상에 적합한 배우자를 찾아 그들의 만남을 주선하는 일을 담당합니다. 상담을 통해 회원의 학력, 신체 조건, 직업 등의 인적 사항과 이상형, 인생관, 용모, 태도 등에 대한 정보를 수집·기록합니다. 커플 연결 시스템을 이용하거나 또는 상담원의 전문적인 의견과 경험을 가지고 회원에게 적합한 상대를 찾고, 그들의 만남을 주선합니다. 만남 주선 후, 회원의 반응을 확인하여 지속적인 만남을 유지할 것인지 또는 회원에게 새로운 만남을 주선할 것인지를 결정합니다.', '["이벤트연출과","미용과","패션디자인과"]', 33580000, '향후 커플매니저의 관련 직업인 결혼상담원 및 웨딩플래너의 일자리 규모는 다소 감소할 것으…', '[]', '매니지먼트 관련직', '2026-04-06 07:49:23.911508');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (614, '1259', '마술사', '설치·정비·생산직', '마술사는 재빠른 손 기술, 카드, 동전, 마술 상자 등을 사용하여 신기한 속임수를 개발하고, 무대에 올라 관중들 앞에서 다양한 마술 공연을 합니다. 마술 공연을 위해 도구, 음악 조명, 무대장치 등을 준비하고 공연을 기획합니다. 마술을 개발하기 위해 기술을 연구하고, 마술 도구를 직접 제작하기도 합니다. 마술사는 공연 일정 외에도 학교나 학원 등에서 마술 관련 강의를 하기도 합니다.', '["레크리에이션과"]', 45790000, '향후 마술사의 관련 직업인 공연기획자의 일자리 규모는 다소 증가할 것으로 전망됩니다. 여…', '[]', '디자인 관련직', '2026-04-06 07:49:24.267965');
