INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (620, '1277', '건축사', '설치·정비·생산직', '건축사는 건축주(고객)의 의뢰를 받아 조형미, 경제성, 안전성, 기능성 등을 고려하여 주택, 사무용 빌딩 등의 건축물을 계획하고 설계하는 일을 합니다. 스케치 및 모형을 준비하고, 전문 지식을 바탕으로 건축계획안과 설계도를 작성합니다. 설계도의 내용이 공사 과정에 정확히 반영되는지를 확인하는 감리 업무를 합니다. 건물의 건설 및 유지 활동을 지휘하거나 건축주 및 시공자에게 조언과 기술 지도를 합니다.', '["건축과","건축공학과","실내디자인과","실내디자인학과"]', 50760000, '향후 건축사의 관련 직업인 건축설계사는 현 상태를 유지하거나 다소 증가할 것으로 전망됩니…', '["건축사","건설기계기술사","건축구조기술사"]', '공학 전문직', '2026-04-06 07:49:26.364197');
