INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (672, '1433', '발명가', '연구직 및 공학 기술직', '발명가는 지금까지 없던 기술이나 물건을 새로 생각하여 만들어 내는 일을 전문적으로 하는 사람으로, 새로운 아이디어를 생각해 내고 시제품을 만듭니다. 자신이 생각해 낸 발명품의 개요를 적어 개인이 직접 특허청에 특허출원을 신청하거나 특허사무소 또는 변리사를 통하여 특허를 신청하기도 합니다. 중소기업이나 대기업 등에 특허법에 의하여 발명을 독점적으로 이용할 수 있는 권리인이 자신의 발명 특허권을 팔기도 합니다. 자신이 발명한 특허기술을 바탕으로 벤처회사를 설립하거나 상품화하여 팔기도 합니다.', '["벤처창업학과"]', NULL, '향후 발명가의 관련 직업인 상품기획자의 일자리 규모는 다소 증가하는 수준이 될 전망입니다…', '[]', '디자인 관련직', '2026-04-06 07:49:44.724586');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (673, '1436', '신약개발연구원', '연구직 및 공학 기술직', '신약개발연구원은 새로운 의약품을 개발하기 위해 기초연구와 응용연구를 수행합니다. 의약품 개발을 위한 국내·외 각종 전문 자료와 정보를 수집하여 분석합니다. 사람, 동식물 등 생물의 기관, 조직, 생명 작용에 영향을 미치는 물질의 효과를 연구하고, 새롭게 개량된 의약품을 연구·개발합니다. 의약품의 원료를 시험·분석하고, 원료의 혼합 비율을 조절하여 더 나은 제품으로 개량하기도 합니다.', '["생명공학과","화학공학과","생명과학과","유전공학과","생화학과"]', 50000000, '향후 신약개발연구원의 관련 직업인 약학연구원의 일자리 규모는 다소 증가할 전망입니다. 우…', '[]', '이학 전문직', '2026-04-06 07:49:45.074069');
INSERT INTO public.cached_jobs (id, job_seq, job_name, field, description, related_majors, salary, growth, qualifications, holland_code, synced_at) VALUES (674, '1439', '캐스팅디렉터', '연구직 및 공학 기술직', '캐스팅디렉터는 드라마나 영화의 연출을 맡은 PD나 감독의 의도를 파악하여 작품의 장르에 적합하고 상업적인 흥행을 이끌 수 있는 배우를 선정하는 일을 합니다. 오디션을 통하여 신인배우를 선발하거나 활동하고 있는 배우를 선정하여 영화 및 드라마의 배역에 가장 적합한 배우를 섭외합니다. 시나리오를 읽어 본 후 등장인물의 성격을 파악하고, 각 배역에 적합한 배우를 섭외하기 위해 배우들에 대한 정보를 수집하여 분석합니다. 배우를 섭외한 이후에도 리허설 장소 제공이나, 녹음 작업, 시사회 초대에 이르기까지 모든 작업에서 배우의 스케줄을 관리하는 일을 하기도 합니다.', '["연극영화과","연극영화학과","영화과","방송연예과"]', 45790000, '향후 캐스팅디렉터의 관련 직업인 공연기획자의 일자리 규모는 다소 증가할 것으로 전망됩니다…', '[]', '예술기획 관련직', '2026-04-06 07:49:45.471702');
